217	  updateViewFilter: (planViewId: string, filterId: string, patch: Partial<ViewFilter>) => void;
218	  removeViewFilter: (planViewId: string, filterId: string) => void;
219	
220	  setActivity: (e: ActivityEvent[]) => void;
221	  setIdentity: (userId: string, display: string, peerId: string) => void;
222	};
