1	/**
2	 * Per-tool grammar — spec §16.4 / §16.5.
3	 *
4	 * Each tool's interaction model is captured here as plain data so the
5	 * tool can be unit-tested without DOM. The shape is consistent across
6	 * tools so the canvas can switch on `kind` and dispatch input.
7	 */
8	
9	export type { WallLocationLine } from '@bim-ai/core';
10	import type { WallLocationLine } from '@bim-ai/core';
11	
12	export type ToolGrammarKind =
13	  | 'wall'
14	  | 'door'
15	  | 'window'
16	  | 'floor'
17	  | 'roof'
18	  | 'stair'
19	  | 'railing'
20	  | 'room'
21	  | 'dimension'
22	  | 'section'
23	  | 'tag'
24	  | 'align'
25	  | 'split'
26	  | 'trim'
27	  | 'wall-join';
28	
29	export const WALL_LOCATION_LINE_ORDER: WallLocationLine[] = [
30	  'wall-centerline',
31	  'finish-face-exterior',
32	  'finish-face-interior',
33	  'core-centerline',
34	  'core-face-exterior',
35	  'core-face-interior',
36	];
37	
38	/** Cycle through the §16.4.1 location-line set on `Tab`. */
39	export function cycleWallLocationLine(current: WallLocationLine): WallLocationLine {
40	  const idx = WALL_LOCATION_LINE_ORDER.indexOf(current);
41	  if (idx < 0) return WALL_LOCATION_LINE_ORDER[0]!;
42	  return WALL_LOCATION_LINE_ORDER[(idx + 1) % WALL_LOCATION_LINE_ORDER.length]!;
43	}
44	
45	/** Wall tool state machine — minimum necessary to drive a chain mode
46	 * without leaking pointer details into the controller. */
47	export interface WallChainState {
48	  active: boolean;
49	  startMm: { xMm: number; yMm: number } | null;
50	  /** Locked endpoint after a click; chain mode begins from here. */
51	  chainAnchorMm: { xMm: number; yMm: number } | null;
52	  locationLine: WallLocationLine;
53	}
54	
55	export function initialWallChainState(): WallChainState {
56	  return {
57	    active: false,
58	    startMm: null,
59	    chainAnchorMm: null,
60	    locationLine: 'wall-centerline',
61	  };
62	}
63	
64	export type WallChainEvent =
65	  | { kind: 'tool-activated' }
66	  | { kind: 'tool-deactivated' }
67	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
68	  | { kind: 'cancel' }
69	  | { kind: 'tab-cycle-location' }
70	  | { kind: 'enter-finish' };
71	
72	export interface WallChainEffect {
73	  /** Wall span to commit, when a 2nd click closes a segment. */
74	  commitSegment?: {
75	    startMm: { xMm: number; yMm: number };
76	    endMm: { xMm: number; yMm: number };
77	    locationLine: WallLocationLine;
78	  };
79	  /** True when the tool stays active after the event. */
80	  stillActive: boolean;
81	  /** True when this event broke the chain (Esc). */
82	  chainBroken?: boolean;
83	}
84	
85	export function reduceWallChain(
86	  state: WallChainState,
87	  event: WallChainEvent,
88	): { state: WallChainState; effect: WallChainEffect } {
89	  if (event.kind === 'tool-activated') {
90	    return {
91	      state: { ...state, active: true, startMm: null, chainAnchorMm: null },
92	      effect: { stillActive: true },
93	    };
94	  }
95	  if (event.kind === 'tool-deactivated') {
96	    return {
97	      state: { ...initialWallChainState() },
98	      effect: { stillActive: false },
99	    };
100	  }
101	  if (!state.active) {
102	    return { state, effect: { stillActive: false } };
103	  }
104	  if (event.kind === 'tab-cycle-location') {
105	    return {
106	      state: { ...state, locationLine: cycleWallLocationLine(state.locationLine) },
107	      effect: { stillActive: true },
108	    };
109	  }
110	  if (event.kind === 'cancel') {
111	    return {
112	      state: { ...state, startMm: null, chainAnchorMm: null },
113	      effect: { stillActive: true, chainBroken: true },
114	    };
115	  }
116	  if (event.kind === 'enter-finish') {
117	    return {
118	      state: { ...initialWallChainState() },
119	      effect: { stillActive: false },
120	    };
121	  }
122	  // click
123	  const start = state.chainAnchorMm ?? state.startMm;
124	  if (!start) {
125	    return {
126	      state: { ...state, startMm: event.pointMm, chainAnchorMm: null },
127	      effect: { stillActive: true },
128	    };
129	  }
130	  const segment = {
131	    startMm: start,
132	    endMm: event.pointMm,
133	    locationLine: state.locationLine,
134	  };
135	  return {
136	    state: { ...state, startMm: null, chainAnchorMm: event.pointMm },
137	    effect: { commitSegment: segment, stillActive: true },
138	  };
139	}
140	
141	/* ────────────────────────────────────────────────────────────────────── */
142	/* Door / Window — §16.4.2 / §16.4.3                                       */
143	/* ────────────────────────────────────────────────────────────────────── */
144	
145	export interface HostedOpeningDefaults {
146	  widthMm: number;
147	  heightMm: number;
148	  sillHeightMm?: number;
149	}
150	
151	export type DoorSwing = 'left' | 'right';
152	export type DoorHand = 'in' | 'out';
153	
154	export interface DoorPlacement {
155	  wallId: string;
156	  alongT: number;
157	  widthMm: number;
158	  heightMm: number;
159	  swing: DoorSwing;
160	  hand: DoorHand;
161	}
162	
163	export const DOOR_DEFAULTS: HostedOpeningDefaults & {
164	  swing: DoorSwing;
165	  hand: DoorHand;
166	} = {
167	  widthMm: 900,
168	  heightMm: 2100,
169	  swing: 'left',
170	  hand: 'in',
171	};
172	
173	/** Spacebar flips swing side; Tab flips hand. */
174	export function flipDoorSwing(swing: DoorSwing): DoorSwing {
175	  return swing === 'left' ? 'right' : 'left';
176	}
177	
178	export function flipDoorHand(hand: DoorHand): DoorHand {
179	  return hand === 'in' ? 'out' : 'in';
180	}
181	
182	export const WINDOW_DEFAULTS: HostedOpeningDefaults = {
183	  widthMm: 1200,
184	  heightMm: 1500,
185	  sillHeightMm: 900,
186	};
187	
188	/* ────────────────────────────────────────────────────────────────────── */
189	/* Floor — §16.4.4                                                          */
190	/* ────────────────────────────────────────────────────────────────────── */
191	
192	export type FloorMode = 'pick-walls' | 'sketch';
193	
194	export interface FloorState {
195	  mode: FloorMode;
196	  sketchPolygonMm: { xMm: number; yMm: number }[];
197	  pickedWallIds: string[];
198	  thicknessMm: number;
199	}
200	
201	export function initialFloorState(): FloorState {
202	  return {
203	    mode: 'pick-walls',
204	    sketchPolygonMm: [],
205	    pickedWallIds: [],
206	    thicknessMm: 220,
207	  };
208	}
209	
210	export function toggleFloorMode(mode: FloorMode): FloorMode {
211	  return mode === 'pick-walls' ? 'sketch' : 'pick-walls';
212	}
213	
214	/* ────────────────────────────────────────────────────────────────────── */
215	/* Roof — §16.4.5                                                           */
216	/* ────────────────────────────────────────────────────────────────────── */
217	
218	export type RoofType = 'gable' | 'hip' | 'flat' | 'shed';
219	
220	export interface RoofState {
221	  type: RoofType;
222	  slopeDeg: number;
223	  /** Per-edge slope override; key is edge index. */
224	  edgeSlopes: Record<number, boolean>;
225	  eaveOverhangMm: number;
226	}
227	
228	export function initialRoofState(): RoofState {
229	  return {
230	    type: 'gable',
231	    slopeDeg: 35,
232	    edgeSlopes: {},
233	    eaveOverhangMm: 600,
234	  };
235	}
236	
237	export function toggleEdgeSlope(state: RoofState, edgeIdx: number): RoofState {
238	  const next = { ...state.edgeSlopes };
239	  next[edgeIdx] = !state.edgeSlopes[edgeIdx];
240	  return { ...state, edgeSlopes: next };
241	}
242	
243	/* ────────────────────────────────────────────────────────────────────── */
244	/* Stair — §16.4.6                                                          */
245	/* ────────────────────────────────────────────────────────────────────── */
246	
247	export type StairType = 'straight' | 'l-shape' | 'u-shape' | 'spiral';
248	
249	export interface StairCalcInput {
250	  baseLevelElevMm: number;
251	  topLevelElevMm: number;
252	  preferredRiserMm?: number;
253	  preferredTreadMm?: number;
254	}
255	
256	export interface StairCalcOutput {
257	  riserMm: number;
258	  treadMm: number;
259	  riserCount: number;
260	  treadCount: number;
261	  totalRiseMm: number;
262	}
263	
264	export const STAIR_RISER_MM_DEFAULT = 175;
265	export const STAIR_TREAD_MM_DEFAULT = 280;
266	
267	/** Auto-compute risers/treads for a straight run between two levels. */
268	export function computeStairRun(input: StairCalcInput): StairCalcOutput {
269	  const totalRise = input.topLevelElevMm - input.baseLevelElevMm;
270	  if (totalRise <= 0) {
271	    return {
272	      riserMm: STAIR_RISER_MM_DEFAULT,
273	      treadMm: STAIR_TREAD_MM_DEFAULT,
274	      riserCount: 0,
275	      treadCount: 0,
276	      totalRiseMm: 0,
277	    };
278	  }
279	  const desired = input.preferredRiserMm ?? STAIR_RISER_MM_DEFAULT;
280	  const riserCount = Math.max(2, Math.round(totalRise / desired));
281	  const riserMm = totalRise / riserCount;
282	  const treadMm = input.preferredTreadMm ?? STAIR_TREAD_MM_DEFAULT;
283	  return {
284	    riserMm,
285	    treadMm,
286	    riserCount,
287	    treadCount: riserCount - 1,
288	    totalRiseMm: totalRise,
289	  };
290	}
291	
292	/* ────────────────────────────────────────────────────────────────────── */
293	/* Railing — §16.4.7                                                        */
294	/* ────────────────────────────────────────────────────────────────────── */
295	
296	export type RailingHostKind = 'stair' | 'slab-edge' | 'sketch-path';
297	
298	export interface RailingDefaults {
299	  style: 'horizontal-bars-5x30';
300	  totalHeightMm: number;
301	  baluster: {
302	    spacingMm: number;
303	    diameterMm: number;
304	  };
305	}
306	
307	export const RAILING_DEFAULTS: RailingDefaults = {
308	  style: 'horizontal-bars-5x30',
309	  totalHeightMm: 1100,
310	  baluster: { spacingMm: 100, diameterMm: 30 },
311	};
312	
313	/* ────────────────────────────────────────────────────────────────────── */
314	/* Room marker — §16.4.8                                                    */
315	/* ────────────────────────────────────────────────────────────────────── */
316	
317	export interface RoomMarkerInput {
318	  /** Closed boundary forming the room — typically the auto-detected
319	   * polygon under the cursor. */
320	  outlineMm: { xMm: number; yMm: number }[];
321	}
322	
323	export function centroidMm(outline: { xMm: number; yMm: number }[]): { xMm: number; yMm: number } {
324	  if (outline.length === 0) return { xMm: 0, yMm: 0 };
325	  let area = 0;
326	  let cx = 0;
327	  let cy = 0;
328	  for (let i = 0; i < outline.length; i++) {
329	    const a = outline[i]!;
330	    const b = outline[(i + 1) % outline.length]!;
331	    const cross = a.xMm * b.yMm - b.xMm * a.yMm;
332	    area += cross;
333	    cx += (a.xMm + b.xMm) * cross;
334	    cy += (a.yMm + b.yMm) * cross;
335	  }
336	  if (area === 0) {
337	    const sum = outline.reduce((acc, p) => ({ xMm: acc.xMm + p.xMm, yMm: acc.yMm + p.yMm }), {
338	      xMm: 0,
339	      yMm: 0,
340	    });
341	    return { xMm: sum.xMm / outline.length, yMm: sum.yMm / outline.length };
342	  }
343	  area /= 2;
344	  return { xMm: cx / (6 * area), yMm: cy / (6 * area) };
345	}
346	
347	/* ────────────────────────────────────────────────────────────────────── */
348	/* Dimension — §16.4.9                                                      */
349	/* ────────────────────────────────────────────────────────────────────── */
350	
351	export type DimensionKind = 'linear' | 'aligned' | 'angular' | 'radial' | 'diameter';
352	
353	export const DIMENSION_HOTKEYS: Record<DimensionKind, string> = {
354	  linear: 'L',
355	  aligned: 'A',
356	  angular: 'G',
357	  radial: 'Q',
358	  diameter: 'Shift+Q',
359	};
360	
361	export interface DimensionState {
362	  kind: DimensionKind;
363	  firstWitnessMm: { xMm: number; yMm: number } | null;
364	  secondWitnessMm: { xMm: number; yMm: number } | null;
365	}
366	
367	export function initialDimensionState(): DimensionState {
368	  return { kind: 'linear', firstWitnessMm: null, secondWitnessMm: null };
369	}
370	
371	export function setDimensionKind(state: DimensionState, kind: DimensionKind): DimensionState {
372	  return { ...state, kind };
373	}
374	
375	/* ────────────────────────────────────────────────────────────────────── */
376	/* Section — §16.4.10                                                       */
377	/* ────────────────────────────────────────────────────────────────────── */
378	
379	export interface SectionDraftState {
380	  startMm: { xMm: number; yMm: number } | null;
381	  endMm: { xMm: number; yMm: number } | null;
382	  /** +1 means depth axis is to the right of the line direction. */
383	  depthSign: 1 | -1;
384	}
385	
386	export function initialSectionDraft(): SectionDraftState {
387	  return { startMm: null, endMm: null, depthSign: 1 };
388	}
389	
390	export function flipSectionDepth(state: SectionDraftState): SectionDraftState {
391	  return { ...state, depthSign: state.depthSign === 1 ? -1 : 1 };
392	}
393	
394	/* ────────────────────────────────────────────────────────────────────── */
395	/* Tag subdropdown — §16.5                                                  */
396	/* ────────────────────────────────────────────────────────────────────── */
397	
398	export type TagFamily = 'tag-door' | 'tag-window' | 'tag-wall' | 'tag-room' | 'tag-by-category';
399	
400	export const TAG_FAMILIES: { id: TagFamily; label: string }[] = [
401	  { id: 'tag-door', label: 'Tag Door' },
402	  { id: 'tag-window', label: 'Tag Window' },
403	  { id: 'tag-wall', label: 'Tag Wall' },
404	  { id: 'tag-room', label: 'Tag Room' },
405	  { id: 'tag-by-category', label: 'Tag by Category' },
406	];
407	
408	/* ────────────────────────────────────────────────────────────────────── */
409	/* Align — §16 Modify                                                       */
410	/* ────────────────────────────────────────────────────────────────────── */
411	
412	export interface AlignState {
413	  phase: 'pick-reference' | 'pick-element';
414	  referenceMm: { xMm: number; yMm: number } | null;
415	}
416	
417	export type AlignEvent =
418	  | { kind: 'activate' }
419	  | { kind: 'deactivate' }
420	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
421	  | { kind: 'cancel' };
422	
423	export interface AlignEffect {
424	  commitAlign?: {
425	    referenceMm: { xMm: number; yMm: number };
426	    targetMm: { xMm: number; yMm: number };
427	  };
428	  stillActive: boolean;
429	}
430	
431	export function initialAlignState(): AlignState {
432	  return { phase: 'pick-reference', referenceMm: null };
433	}
434	
435	export function reduceAlign(
436	  state: AlignState,
437	  event: AlignEvent,
438	): { state: AlignState; effect: AlignEffect } {
439	  if (event.kind === 'activate') {
440	    return { state: { phase: 'pick-reference', referenceMm: null }, effect: { stillActive: true } };
441	  }
442	  if (event.kind === 'deactivate') {
443	    return {
444	      state: { phase: 'pick-reference', referenceMm: null },
445	      effect: { stillActive: false },
446	    };
447	  }
448	  if (event.kind === 'cancel') {
449	    return { state: { phase: 'pick-reference', referenceMm: null }, effect: { stillActive: true } };
450	  }
451	  // click
452	  if (state.phase === 'pick-reference') {
453	    return {
454	      state: { phase: 'pick-element', referenceMm: event.pointMm },
455	      effect: { stillActive: true },
456	    };
457	  }
458	  // pick-element + click → commit and return to pick-reference for next pair
459	  return {
460	    state: { phase: 'pick-reference', referenceMm: null },
461	    effect: {
462	      commitAlign: { referenceMm: state.referenceMm!, targetMm: event.pointMm },
463	      stillActive: true,
464	    },
465	  };
466	}
467	
468	/* ────────────────────────────────────────────────────────────────────── */
469	/* Split — §16 Modify                                                       */
470	/* ────────────────────────────────────────────────────────────────────── */
471	
472	export interface SplitState {
473	  active: boolean;
474	}
475	
476	export type SplitEvent =
477	  | { kind: 'activate' }
478	  | { kind: 'deactivate' }
479	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
480	  | { kind: 'cancel' };
481	
482	export interface SplitEffect {
483	  commitSplit?: { pointMm: { xMm: number; yMm: number } };
484	  stillActive: boolean;
485	}
486	
487	export function initialSplitState(): SplitState {
488	  return { active: false };
489	}
490	
491	export function reduceSplit(
492	  state: SplitState,
493	  event: SplitEvent,
494	): { state: SplitState; effect: SplitEffect } {
495	  if (event.kind === 'activate') {
496	    return { state: { active: true }, effect: { stillActive: true } };
497	  }
498	  if (event.kind === 'deactivate') {
499	    return { state: { active: false }, effect: { stillActive: false } };
500	  }
501	  if (event.kind === 'cancel') {
502	    return { state, effect: { stillActive: true } };
503	  }
504	  if (!state.active) {
505	    return { state, effect: { stillActive: false } };
506	  }
507	  // click while active → emit split, stay active (Revit stays in Split mode)
508	  return {
509	    state,
510	    effect: { commitSplit: { pointMm: event.pointMm }, stillActive: true },
511	  };
512	}
513	
514	/* ────────────────────────────────────────────────────────────────────── */
515	/* Trim / Extend — §16 Modify                                               */
516	/* ────────────────────────────────────────────────────────────────────── */
517	
518	export interface TrimState {
519	  phase: 'pick-reference' | 'pick-target';
520	  referenceId: string | null;
521	}
522	
523	export type TrimEvent =
524	  | { kind: 'activate' }
525	  | { kind: 'deactivate' }
526	  | { kind: 'click-reference'; elementId: string }
527	  | { kind: 'click-target'; elementId: string; endHint: 'start' | 'end' }
528	  | { kind: 'cancel' };
529	
530	export interface TrimEffect {
531	  commitTrim?: { referenceId: string; targetId: string; endHint: 'start' | 'end' };
532	  stillActive: boolean;
533	}
534	
535	export function initialTrimState(): TrimState {
536	  return { phase: 'pick-reference', referenceId: null };
537	}
538	
539	export function reduceTrim(
540	  state: TrimState,
541	  event: TrimEvent,
542	): { state: TrimState; effect: TrimEffect } {
543	  if (event.kind === 'activate') {
544	    return {
545	      state: { phase: 'pick-reference', referenceId: null },
546	      effect: { stillActive: true },
547	    };
548	  }
549	  if (event.kind === 'deactivate') {
550	    return {
551	      state: { phase: 'pick-reference', referenceId: null },
552	      effect: { stillActive: false },
553	    };
554	  }
555	  if (event.kind === 'cancel') {
556	    return {
557	      state: { phase: 'pick-reference', referenceId: null },
558	      effect: { stillActive: true },
559	    };
560	  }
561	  if (event.kind === 'click-reference') {
562	    return {
563	      state: { phase: 'pick-target', referenceId: event.elementId },
564	      effect: { stillActive: true },
565	    };
566	  }
567	  // click-target
568	  if (state.phase !== 'pick-target' || !state.referenceId) {
569	    return { state, effect: { stillActive: true } };
570	  }
571	  return {
572	    state: { phase: 'pick-reference', referenceId: null },
573	    effect: {
574	      commitTrim: {
575	        referenceId: state.referenceId,
576	        targetId: event.elementId,
577	        endHint: event.endHint,
578	      },
579	      stillActive: true,
580	    },
581	  };
582	}
583	
584	/* ────────────────────────────────────────────────────────────────────── */
585	/* Wall Join — §16 Modify                                                   */
586	/* ────────────────────────────────────────────────────────────────────── */
587	
588	export type WallJoinVariant = 'miter' | 'butt' | 'square';
589	
590	const WALL_JOIN_VARIANTS: WallJoinVariant[] = ['miter', 'butt', 'square'];
591	
592	export interface WallJoinState {
593	  phase: 'idle' | 'selected';
594	  cornerMm: { xMm: number; yMm: number } | null;
595	  wallIds: string[];
596	  joinVariant: WallJoinVariant;
597	}
598	
599	export type WallJoinEvent =
600	  | { kind: 'activate' }
601	  | { kind: 'deactivate' }
602	  | { kind: 'click-corner'; cornerMm: { xMm: number; yMm: number }; wallIds: string[] }
603	  | { kind: 'cycle' }
604	  | { kind: 'accept' }
605	  | { kind: 'cancel' };
606	
607	export interface WallJoinEffect {
608	  commitJoin?: { wallIds: string[]; variant: WallJoinVariant };
609	  stillActive: boolean;
610	}
611	
612	export function initialWallJoinState(): WallJoinState {
613	  return { phase: 'idle', cornerMm: null, wallIds: [], joinVariant: 'miter' };
614	}
615	
616	export function reduceWallJoin(
617	  state: WallJoinState,
618	  event: WallJoinEvent,
619	): { state: WallJoinState; effect: WallJoinEffect } {
620	  if (event.kind === 'activate') {
621	    return { state: initialWallJoinState(), effect: { stillActive: true } };
622	  }
623	  if (event.kind === 'deactivate') {
624	    return { state: initialWallJoinState(), effect: { stillActive: false } };
625	  }
626	  if (event.kind === 'cancel') {
627	    return { state: initialWallJoinState(), effect: { stillActive: true } };
628	  }
629	  if (event.kind === 'click-corner') {
630	    return {
631	      state: {
632	        phase: 'selected',
633	        cornerMm: event.cornerMm,
634	        wallIds: event.wallIds,
635	        joinVariant: 'miter',
636	      },
637	      effect: { stillActive: true },
638	    };
639	  }
640	  if (event.kind === 'cycle' && state.phase === 'selected') {
641	    const idx = WALL_JOIN_VARIANTS.indexOf(state.joinVariant);
642	    const next = WALL_JOIN_VARIANTS[(idx + 1) % WALL_JOIN_VARIANTS.length]!;
643	    return { state: { ...state, joinVariant: next }, effect: { stillActive: true } };
644	  }
645	  if (event.kind === 'accept' && state.phase === 'selected') {
646	    return {
647	      state: initialWallJoinState(),
648	      effect: { commitJoin: { wallIds: state.wallIds, variant: state.joinVariant }, stillActive: true },
649	    };
650	  }
651	  return { state, effect: { stillActive: true } };
652	}
653	
654	/* ────────────────────────────────────────────────────────────────────── */
655	/* Wall Opening — §16 Openings                                            */
656	/* ────────────────────────────────────────────────────────────────────── */
657	
658	export interface WallOpeningState {
659	  phase: 'pick-wall' | 'define-rect';
660	  hostWallId: string | null;
661	  anchorMm: { xMm: number; yMm: number } | null;
662	}
663	
664	export type WallOpeningEvent =
665	  | { kind: 'activate' }
666	  | { kind: 'deactivate' }
667	  | { kind: 'click-wall'; wallId: string; pointMm: { xMm: number; yMm: number } }
668	  | { kind: 'drag-end'; cornerMm: { xMm: number; yMm: number } }
669	  | { kind: 'cancel' };
670	
671	export interface WallOpeningEffect {
672	  commitWallOpening?: {
673	    hostWallId: string;
674	    anchorMm: { xMm: number; yMm: number };
675	    cornerMm: { xMm: number; yMm: number };
676	  };
677	  stillActive: boolean;
678	}
679	
680	export function initialWallOpeningState(): WallOpeningState {
681	  return { phase: 'pick-wall', hostWallId: null, anchorMm: null };
682	}
683	
684	export function reduceWallOpening(
685	  state: WallOpeningState,
686	  event: WallOpeningEvent,
687	): { state: WallOpeningState; effect: WallOpeningEffect } {
688	  if (event.kind === 'activate') {
689	    return { state: initialWallOpeningState(), effect: { stillActive: true } };
690	  }
691	  if (event.kind === 'deactivate') {
692	    return { state: initialWallOpeningState(), effect: { stillActive: false } };
693	  }
694	  if (event.kind === 'cancel') {
695	    return { state: initialWallOpeningState(), effect: { stillActive: true } };
696	  }
697	  if (event.kind === 'click-wall' && state.phase === 'pick-wall') {
698	    return {
699	      state: { phase: 'define-rect', hostWallId: event.wallId, anchorMm: event.pointMm },
700	      effect: { stillActive: true },
701	    };
702	  }
703	  if (event.kind === 'drag-end' && state.phase === 'define-rect' && state.hostWallId && state.anchorMm) {
704	    return {
705	      state: initialWallOpeningState(),
706	      effect: {
707	        commitWallOpening: {
708	          hostWallId: state.hostWallId,
709	          anchorMm: state.anchorMm,
710	          cornerMm: event.cornerMm,
711	        },
712	        stillActive: true,
713	      },
714	    };
715	  }
716	  return { state, effect: { stillActive: true } };
717	}
718	
719	/* ────────────────────────────────────────────────────────────────────── */
720	/* Shaft — §16 Openings                                                   */
721	/* ────────────────────────────────────────────────────────────────────── */
722	
723	export interface ShaftState {
724	  phase: 'idle' | 'sketch';
725	  verticesMm: Array<{ xMm: number; yMm: number }>;
726	}
727	
728	export type ShaftEvent =
729	  | { kind: 'activate' }
730	  | { kind: 'deactivate' }
731	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
732	  | { kind: 'close-loop' }
733	  | { kind: 'cancel' };
734	
735	export interface ShaftEffect {
736	  commitShaft?: { verticesMm: Array<{ xMm: number; yMm: number }> };
737	  stillActive: boolean;
738	}
739	
740	export function initialShaftState(): ShaftState {
741	  return { phase: 'idle', verticesMm: [] };
742	}
743	
744	export function reduceShaft(
745	  state: ShaftState,
746	  event: ShaftEvent,
747	): { state: ShaftState; effect: ShaftEffect } {
748	  if (event.kind === 'activate') {
749	    return { state: initialShaftState(), effect: { stillActive: true } };
750	  }
751	  if (event.kind === 'deactivate') {
752	    return { state: initialShaftState(), effect: { stillActive: false } };
753	  }
754	  if (event.kind === 'cancel') {
755	    return { state: initialShaftState(), effect: { stillActive: true } };
756	  }
757	  if (event.kind === 'click') {
758	    return {
759	      state: { phase: 'sketch', verticesMm: [...state.verticesMm, event.pointMm] },
760	      effect: { stillActive: true },
761	    };
762	  }
763	  if (event.kind === 'close-loop' && state.verticesMm.length >= 3) {
764	    return {
765	      state: initialShaftState(),
766	      effect: { commitShaft: { verticesMm: state.verticesMm }, stillActive: true },
767	    };
768	  }
769	  return { state, effect: { stillActive: true } };
770	}
771	
772	/* ────────────────────────────────────────────────────────────────────── */
773	/* C16 Column — single-click placement                                      */
774	/* ────────────────────────────────────────────────────────────────────── */
775	
776	export type ColumnState = { phase: 'idle' };
777	
778	export type ColumnEvent =
779	  | { kind: 'activate' }
780	  | { kind: 'deactivate' }
781	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
782	  | { kind: 'cancel' };
783	
784	export interface ColumnEffect {
785	  commitColumn?: { positionMm: { xMm: number; yMm: number } };
786	  stillActive: boolean;
787	}
788	
789	export function initialColumnState(): ColumnState {
790	  return { phase: 'idle' };
791	}
792	
793	export function reduceColumn(
794	  state: ColumnState,
795	  event: ColumnEvent,
796	): { state: ColumnState; effect: ColumnEffect } {
797	  if (event.kind === 'deactivate') {
798	    return { state: initialColumnState(), effect: { stillActive: false } };
799	  }
800	  if (event.kind === 'activate' || event.kind === 'cancel') {
801	    return { state: initialColumnState(), effect: { stillActive: event.kind === 'activate' } };
802	  }
803	  if (event.kind === 'click') {
804	    return {
805	      state: initialColumnState(),
806	      effect: { commitColumn: { positionMm: event.pointMm }, stillActive: true },
807	    };
808	  }
809	  return { state, effect: { stillActive: true } };
810	}
811	
812	/* ────────────────────────────────────────────────────────────────────── */
813	/* C17 Beam — two-click line placement                                      */
814	/* ────────────────────────────────────────────────────────────────────── */
815	
816	export type BeamState =
817	  | { phase: 'idle' }
818	  | { phase: 'first-point'; startMm: { xMm: number; yMm: number } };
819	
820	export type BeamEvent =
821	  | { kind: 'activate' }
822	  | { kind: 'deactivate' }
823	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
824	  | { kind: 'cancel' };
825	
826	export interface BeamEffect {
827	  commitBeam?: { startMm: { xMm: number; yMm: number }; endMm: { xMm: number; yMm: number } };
828	  stillActive: boolean;
829	}
830	
831	export function initialBeamState(): BeamState {
832	  return { phase: 'idle' };
833	}
834	
835	export function reduceBeam(
836	  state: BeamState,
837	  event: BeamEvent,
838	): { state: BeamState; effect: BeamEffect } {
839	  if (event.kind === 'deactivate') {
840	    return { state: initialBeamState(), effect: { stillActive: false } };
841	  }
842	  if (event.kind === 'activate' || event.kind === 'cancel') {
843	    return { state: initialBeamState(), effect: { stillActive: event.kind === 'activate' } };
844	  }
845	  if (event.kind === 'click') {
846	    if (state.phase === 'idle') {
847	      return {
848	        state: { phase: 'first-point', startMm: event.pointMm },
849	        effect: { stillActive: true },
850	      };
851	    }
852	    if (state.phase === 'first-point') {
853	      return {
854	        state: initialBeamState(),
855	        effect: {
856	          commitBeam: { startMm: state.startMm, endMm: event.pointMm },
857	          stillActive: true,
858	        },
859	      };
860	    }
861	  }
862	  return { state, effect: { stillActive: true } };
863	}
