27	
28	/* ────────────────────────────────────────────────────────────────────── */
29	/* Plan palette — token-driven colors used in plan symbology.              */
30	/*                                                                          */
31	/* Read once per render (via getPlanPalette) so that a theme switch picks   */
32	/* up updated `:root` custom-property values. Each token has a defensive    */
33	/* fallback used when the live document has no stylesheet attached (SSR /   */
34	/* jsdom-without-tokens).                                                   */
35	/* ────────────────────────────────────────────────────────────────────── */
36	
37	export interface PlanPalette {
38	  wallFill: string;
39	  wallSelected: string;
40	  doorFill: string;
41	  doorSelected: string;
42	  doorSwing: string;
43	  doorSwingFocus: string;
44	  windowFill: string;
45	  windowSelected: string;
46	  windowSelectedBackline: string;
47	  windowFillBackline: string;
48	  windowGlass: string;
49	  windowGlassFocus: string;
