64	
65	export function readToken(name: string, fallback: string): string {
66	  const v = liveTokenReader().read(name);
67	  return v && v.trim().length > 0 ? v : fallback;
68	}
69	
70	export function getPlanPalette(): PlanPalette {
71	  return {
72	    wallFill: readToken('--cat-wall', '#94a3b8'),
73	    wallSelected: readToken('--color-accent', '#fb923c'),
74	    doorFill: readToken('--cat-door', '#67e8f9'),
75	    doorSelected: readToken('--color-accent', '#fde047'),
76	    doorSwing: readToken('--draft-construction-blue', '#0ea5e9'),
77	    doorSwingFocus: readToken('--draft-hover', '#bae6fd'),
78	    windowFill: readToken('--cat-window', '#9333ea'),
79	    windowSelected: readToken('--color-accent', '#ddd6fe'),
80	    windowSelectedBackline: readToken('--color-accent', '#c4b5fd'),
81	    windowFillBackline: readToken('--cat-window', '#a78bfa'),
82	    windowGlass: readToken('--cat-window', '#7c3aed'),
