100	/** World-space dash gaps for plan linework (grid, room separation) from server tokens. */
101	
102	export function planLinePatternDashWorldUnits(
103	  token: string | null | undefined,
104	): { dashSize: number; gapSize: number } | null {
105	  const t = (token ?? 'solid') as PlanLinePatternToken;
106	  switch (t) {
107	    case 'solid':
108	      return null;
109	    case 'dash_short':
110	      return { dashSize: 0.06, gapSize: 0.04 };
111	    case 'dash_long':
112	      return { dashSize: 0.12, gapSize: 0.06 };
113	    case 'dot':
114	      return { dashSize: 0.02, gapSize: 0.05 };
115	    default:
116	      return null;
117	  }
118	}
