190	export function segmentDir(wall: Extract<Element, { kind: 'wall' }>) {
191	  const dx = ux(wall.end.xMm - wall.start.xMm);
192	
193	  const dz = uz(wall.end.yMm - wall.start.yMm);
194	
195	  const len = Math.max(1e-6, Math.hypot(dx, dz));
196	
197	  return {
198	    lenM: len,
199	
200	    nx: dx / len,
201	
202	    nz: dz / len,
203	  };
204	}
