206	export function centroidMm(poly: Array<{ xMm: number; yMm: number }>): {
207	  xMm: number;
208	  yMm: number;
209	} {
210	  let sx = 0;
211	
212	  let sy = 0;
213	
214	  for (const p of poly) {
215	    sx += p.xMm;
216	
217	    sy += p.yMm;
218	  }
219	
220	  const n = Math.max(1, poly.length);
221	
222	  return { xMm: sx / n, yMm: sy / n };
223	}
224	
225	export function polygonAreaMm2(poly: Array<{ xMm: number; yMm: number }>): number {
226	  let a = 0;
227	
228	  const n = poly.length;
229	
230	  if (n < 3) return 0;
231	
232	  for (let i = 0; i < n; i++) {
233	    const p = poly[i]!;
234	
235	    const q = poly[(i + 1) % n]!;
236	
237	    a += p.xMm * q.yMm - q.xMm * p.yMm;
238	  }
239	
240	  return Math.abs(a / 2);
241	}
