243	function horizontalOutlineMesh(
244	  outlineMm: Array<{ xMm: number; yMm: number }>,
245	  yWorld: number,
246	  color: string,
247	  opacity: number,
248	  pickId: string,
249	): THREE.Mesh {
250	  const shape = new THREE.Shape();
251	
252	  const o = outlineMm[0];
253	
254	  if (!o) return new THREE.Mesh();
255	
256	  shape.moveTo(ux(o.xMm), -uz(o.yMm));
257	
258	  for (let i = 1; i < outlineMm.length; i++) {
259	    const p = outlineMm[i];
260	
261	    if (p) shape.lineTo(ux(p.xMm), -uz(p.yMm));
262	  }
263	
264	  shape.closePath();
265	
266	  const geo = new THREE.ShapeGeometry(shape);
267	
268	  const mesh = new THREE.Mesh(
269	    geo,
270	
271	    new THREE.MeshBasicMaterial({
272	      color,
273	
274	      transparent: true,
275	
276	      opacity,
277	
278	      depthWrite: false,
279	    }),
280	  );
281	
282	  mesh.rotation.x = -Math.PI / 2;
283	
284	  mesh.position.y = yWorld;
285	
286	  mesh.userData.bimPickId = pickId;
287	
288	  return mesh;
289	}
