295	/** Wire-path floor/roof: category-weighted fill + closed outline stroke (pattern from server). */
296	function planFloorRoofOutlineWireGroup(
297	  outlineMm: Array<{ xMm: number; yMm: number }>,
298	  opts: {
299	    kind: 'floor' | 'roof';
300	    pickId: string;
301	    lineWeightHint: number;
302	    linePatternToken?: string | null;
303	    roofGeometrySupportToken?: string | null;
304	  },
305	): THREE.Group {
306	  const grp = new THREE.Group();
307	  const palette = getPlanPalette();
308	  const color = opts.kind === 'floor' ? palette.floorOutline : palette.roofOutline;
309	  const fillY = opts.kind === 'floor' ? PLAN_Y + 0.001 : PLAN_Y + 0.004;
310	  const strokeY = fillY + 0.0004;
311	  const baseOp = opts.kind === 'floor' ? PLAN_FLOOR_FILL_OPACITY_BASE : PLAN_ROOF_FILL_OPACITY_BASE;
312	  const lwh =
313	    Number.isFinite(opts.lineWeightHint) && opts.lineWeightHint > 0 ? opts.lineWeightHint : 1;
314	  const fillOpacity = Math.min(0.34, Math.max(0.06, baseOp * Math.min(1.35, lwh / 1.12)));
315	  grp.add(horizontalOutlineMesh(outlineMm, fillY, color, fillOpacity, opts.pickId));
316	
317	  if (outlineMm.length < 2) {
318	    grp.userData.bimPickId = opts.pickId;
319	    if (opts.kind === 'roof' && opts.roofGeometrySupportToken) {
320	      grp.userData.bimAiRoofGeometrySupportToken = opts.roofGeometrySupportToken;
321	    }
322	    return grp;
323	  }
324	
325	  const pts = outlineMm.map((p) => new THREE.Vector3(ux(p.xMm), strokeY, uz(p.yMm)));
326	  const dashSpec = planLinePatternDashWorldUnits(opts.linePatternToken ?? undefined);
327	  if (dashSpec == null) {
328	    const loop = new THREE.LineLoop(
329	      new THREE.BufferGeometry().setFromPoints(pts),
330	      new THREE.LineBasicMaterial({ color, depthTest: true }),
331	    );
332	    loop.userData.bimPickId = opts.pickId;
333	    grp.add(loop);
334	  } else {
335	    const closed = [...pts, pts[0]!];
336	    const mat = new THREE.LineDashedMaterial({
337	      color,
338	      dashSize: dashSpec.dashSize,
339	      gapSize: dashSpec.gapSize,
340	      depthTest: true,
341	    });
342	    const ln = new THREE.Line(new THREE.BufferGeometry().setFromPoints(closed), mat);
343	    ln.computeLineDistances();
344	    ln.userData.bimPickId = opts.pickId;
345	    grp.add(ln);
346	  }
347	
348	  grp.userData.bimPickId = opts.pickId;
349	  if (opts.kind === 'roof' && opts.roofGeometrySupportToken) {
350	    grp.userData.bimAiRoofGeometrySupportToken = opts.roofGeometrySupportToken;
351	  }
352	  return grp;
353	}
