59	
60	  return {
61	    minX,
62	
63	    maxX,
64	
65	    minZ,
66	
67	    maxZ,
68	
69	    cx: (minX + maxX) / 2,
70	
71	    cz: (minZ + maxZ) / 2,
72	
73	    spanX,
74	
75	    spanZ,
76	  };
