85	export function hostedXZ(
86	  hosted: Extract<Element, { kind: 'door' } | { kind: 'window' }>,
87	  wall: WallElem,
88	): { px: number; pz: number } {
89	  const sx = wall.start.xMm / 1000;
90	  const sz = wall.start.yMm / 1000;
91	  const dx = wall.end.xMm / 1000 - sx;
92	  const dz = wall.end.yMm / 1000 - sz;
93	  const len = Math.max(1e-6, Math.hypot(dx, dz));
94	  const ux = dx / len;
95	  const uz = dz / len;
96	  return {
97	    px: sx + ux * hosted.alongT * len,
98	    pz: sz + uz * hosted.alongT * len,
99	  };
100	}
