102	export function wallYaw(wall: WallElem) {
103	  const sx = wall.start.xMm / 1000;
104	  const sz = wall.start.yMm / 1000;
105	  const ex = wall.end.xMm / 1000;
106	  const ez = wall.end.yMm / 1000;
107	  return Math.atan2(ez - sz, ex - sx);
