110	export function makeFloorSlabMesh(
111	  floor: Extract<Element, { kind: 'floor' }>,
112	  elementsById: Record<string, Element>,
113	  paint: ViewportPaintBundle | null,
114	): THREE.Mesh {
115	  const elev = elevationMForLevel(floor.levelId, elementsById);
116	  const th = THREE.MathUtils.clamp(floor.thicknessMm / 1000, 0.05, 1.8);
117	  const boundary = floor.boundaryMm ?? [];
118	
119	  // Build shape in shape-XY (plan X→shape X, plan Y negated→shape Y).
120	  // After ExtrudeGeometry + rotateX(-π/2): shape X→world X, extrude depth→world Y, −shapeY→world Z.
121	  const shape = new THREE.Shape(
122	    boundary.length >= 3
123	      ? boundary.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))
124	      : [
125	          new THREE.Vector2(0, 0),
126	          new THREE.Vector2(6, 0),
127	          new THREE.Vector2(6, -6),
128	          new THREE.Vector2(0, -6),
129	        ],
130	  );
131	
132	  // Punch holes for any slab openings hosted by this floor.
133	  for (const el of Object.values(elementsById)) {
134	    if (el.kind !== 'slab_opening' || el.hostFloorId !== floor.id) continue;
135	    const hPts = el.boundaryMm ?? [];
136	    if (hPts.length < 3) continue;
137	    shape.holes.push(
138	      new THREE.Path(hPts.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))),
139	    );
140	  }
141	
142	  const geom = new THREE.ExtrudeGeometry(shape, { depth: th, bevelEnabled: false });
143	  geom.rotateX(-Math.PI / 2);
144	
145	  const mesh = new THREE.Mesh(
146	    geom,
147	    new THREE.MeshStandardMaterial({
148	      color: categoryColorOr(paint, 'floor'),
149	      roughness: paint?.categories.floor.roughness ?? 0.9,
150	      transparent: true,
151	      opacity: 0.92,
152	    }),
153	  );
154	  mesh.position.set(0, elev, 0);
155	  mesh.castShadow = true;
156	  mesh.receiveShadow = true;
157	  mesh.userData.bimPickId = floor.id;
158	  addEdges(mesh, 20);
159	  return mesh;
160	}
