164	export type XYPt = { xMm: number; yMm: number };
165	
166	/**
167	 * Offset each edge of a convex (or mildly concave) polygon outward by `dist` mm.
168	 * Shifts each edge line outward and intersects adjacent offset lines to get corners.
169	 */
170	export function offsetPolygonMm(pts: XYPt[], dist: number): XYPt[] {
171	  const n = pts.length;
172	  if (n < 3) return pts.slice();
173	
174	  // Signed area: positive = CCW in standard (right-hand) plan coordinates.
175	  let area2 = 0;
176	  for (let i = 0; i < n; i++) {
177	    const a = pts[i],
178	      b = pts[(i + 1) % n];
179	    area2 += a.xMm * b.yMm - b.xMm * a.yMm;
180	  }
181	  const sign = area2 > 0 ? 1 : -1; // +1 CCW, −1 CW
182	
183	  const result: XYPt[] = [];
184	  for (let i = 0; i < n; i++) {
185	    const A = pts[(i - 1 + n) % n];
186	    const B = pts[i];
187	    const C = pts[(i + 1) % n];
188	
189	    // Outward unit normal of edge A→B: right-perpendicular for CCW.
190	    const dx1 = B.xMm - A.xMm,
191	      dy1 = B.yMm - A.yMm;
192	    const len1 = Math.hypot(dx1, dy1) || 1;
193	    const nx1 = (sign * dy1) / len1,
194	      ny1 = (-sign * dx1) / len1;
195	
196	    // Outward unit normal of edge B→C.
197	    const dx2 = C.xMm - B.xMm,
198	      dy2 = C.yMm - B.yMm;
199	    const len2 = Math.hypot(dx2, dy2) || 1;
200	    const nx2 = (sign * dy2) / len2,
201	      ny2 = (-sign * dx2) / len2;
202	
203	    // Offset origin of each edge line.
204	    const ox1 = A.xMm + nx1 * dist,
205	      oy1 = A.yMm + ny1 * dist;
206	    const ox2 = B.xMm + nx2 * dist,
207	      oy2 = B.yMm + ny2 * dist;
208	    const ux1 = dx1 / len1,
209	      uy1 = dy1 / len1;
210	    const ux2 = dx2 / len2,
211	      uy2 = dy2 / len2;
212	
213	    // Intersect the two offset lines.
214	    const det = ux1 * uy2 - uy1 * ux2;
215	    if (Math.abs(det) < 1e-9) {
216	      result.push({ xMm: ox2, yMm: oy2 });
217	    } else {
218	      const t = ((ox2 - ox1) * uy2 - (oy2 - oy1) * ux2) / det;
219	      result.push({ xMm: ox1 + t * ux1, yMm: oy1 + t * uy1 });
220	    }
221	  }
222	  return result;
223	}
