225	function _polygonAreaMm2(pts: XYPt[]): number {
226	  let s = 0;
227	  for (let i = 0; i < pts.length; i++) {
228	    const a = pts[i],
229	      b = pts[(i + 1) % pts.length];
230	    s += a.xMm * b.yMm - b.xMm * a.yMm;
231	  }
232	  return Math.abs(s) / 2;
233	}
234	
235	function _convexHullAreaMm2(pts: XYPt[]): number {
236	  const n = pts.length;
237	  if (n < 3) return 0;
238	  // Gift-wrapping convex hull.
239	  let start = 0;
240	  for (let i = 1; i < n; i++) if (pts[i].xMm < pts[start].xMm) start = i;
241	  const hull: XYPt[] = [];
242	  let cur = start;
243	  do {
244	    hull.push(pts[cur]);
245	    let next = (cur + 1) % n;
246	    for (let i = 0; i < n; i++) {
247	      const cross =
248	        (pts[next].xMm - pts[cur].xMm) * (pts[i].yMm - pts[cur].yMm) -
249	        (pts[next].yMm - pts[cur].yMm) * (pts[i].xMm - pts[cur].xMm);
250	      if (cross < 0) next = i;
251	    }
252	    cur = next;
253	  } while (cur !== start && hull.length <= n);
254	  return _polygonAreaMm2(hull);
255	}
256	
257	/** Returns polygon area / convex hull area. < 0.85 indicates an L-shaped footprint. */
258	function _compactnessRatio(pts: XYPt[]): number {
259	  const hullArea = _convexHullAreaMm2(pts);
260	  if (hullArea < 1) return 1;
261	  return _polygonAreaMm2(pts) / hullArea;
262	}
