643	/**
644	 * Split an L-shaped footprint into two overlapping rectangles, build a gable
645	 * geometry for each, and merge them. Adds a triangular valley face at the
646	 * internal junction.
647	 */
648	function _buildLShapeGeometry(
649	  rawPts: XYPt[],
650	  ovMm: number,
651	  eaveY: number,
652	  slopeRad: number,
653	): THREE.BufferGeometry {
654	  const b = xzBoundsMm(rawPts);
655	  const tol = Math.max((b.spanX + b.spanZ) * 0.02, 5); // 2% of span
656	
657	  // Find which AABB corner is absent from the polygon — that tells us the
658	  // missing rectangle and which vertex is the reflex step.
659	  const aabbCorners = [
660	    { side: 'sw', x: b.minX, y: b.minZ },
661	    { side: 'se', x: b.maxX, y: b.minZ },
662	    { side: 'nw', x: b.minX, y: b.maxZ },
663	    { side: 'ne', x: b.maxX, y: b.maxZ },
664	  ] as const;
665	
666	  let missingSide: 'sw' | 'se' | 'nw' | 'ne' = 'ne';
667	  for (const c of aabbCorners) {
668	    if (!rawPts.some((p) => Math.abs(p.xMm - c.x) < tol && Math.abs(p.yMm - c.y) < tol)) {
669	      missingSide = c.side;
670	      break;
671	    }
672	  }
673	
674	  // Find the reflex vertex (the step vertex adjacent to the missing corner).
675	  // It shares one coordinate with each of the two AABB corners flanking the missing one.
676	  let rv: XYPt = rawPts[0];
677	  {
678	    let area2 = 0;
679	    const n = rawPts.length;
680	    for (let i = 0; i < n; i++) {
681	      const a = rawPts[i],
682	        c = rawPts[(i + 1) % n];
683	      area2 += a.xMm * c.yMm - c.xMm * a.yMm;
684	    }
685	    const wsign = area2 > 0 ? 1 : -1;
686	    for (let i = 0; i < n; i++) {
687	      const A = rawPts[(i - 1 + n) % n];
688	      const B = rawPts[i];
689	      const C = rawPts[(i + 1) % n];
690	      const cross = (B.xMm - A.xMm) * (C.yMm - B.yMm) - (B.yMm - A.yMm) * (C.xMm - B.xMm);
691	      if (cross * wsign < 0) {
692	        rv = B;
693	        break;
694	      }
695	    }
696	  }
697	
698	  const ovOff = ovMm > 0 ? ovMm : 0;
699	
700	  // Build the two sub-rectangle AABB bounds (in mm) then convert to metres with overhang.
701	  let r1: { x0: number; x1: number; z0: number; z1: number };
702	  let r2: { x0: number; x1: number; z0: number; z1: number };
703	
704	  // Strategy: the two rectangles share one full dimension and each covers the
705	  // "arm" of the L.  We choose the split so the rectangles overlap at the step.
706	  switch (missingSide) {
707	    case 'ne': // missing top-right → step at (rv.xMm, rv.yMm)
708	      r1 = { x0: b.minX, x1: b.maxX, z0: b.minZ, z1: rv.yMm }; // full-width bottom
709	      r2 = { x0: b.minX, x1: rv.xMm, z0: b.minZ, z1: b.maxZ }; // left-arm full height
710	      break;
711	    case 'nw': // missing top-left
712	      r1 = { x0: b.minX, x1: b.maxX, z0: b.minZ, z1: rv.yMm };
713	      r2 = { x0: rv.xMm, x1: b.maxX, z0: b.minZ, z1: b.maxZ };
714	      break;
715	    case 'se': // missing bottom-right
716	      r1 = { x0: b.minX, x1: b.maxX, z0: rv.yMm, z1: b.maxZ };
717	      r2 = { x0: b.minX, x1: rv.xMm, z0: b.minZ, z1: b.maxZ };
718	      break;
719	    case 'sw': // missing bottom-left
720	    default:
721	      r1 = { x0: b.minX, x1: b.maxX, z0: rv.yMm, z1: b.maxZ };
722	      r2 = { x0: rv.xMm, x1: b.maxX, z0: b.minZ, z1: b.maxZ };
723	      break;
724	  }
725	
726	  function toM(r: { x0: number; x1: number; z0: number; z1: number }) {
727	    return {
728	      ox0: r.x0 / 1000 - ovOff / 1000,
729	      ox1: r.x1 / 1000 + ovOff / 1000,
730	      oz0: r.z0 / 1000 - ovOff / 1000,
731	      oz1: r.z1 / 1000 + ovOff / 1000,
732	    };
733	  }
734	
735	  const m1 = toM(r1),
736	    m2 = toM(r2);
737	  const ax1 = m1.ox1 - m1.ox0 >= m1.oz1 - m1.oz0;
738	  const ax2 = m2.ox1 - m2.ox0 >= m2.oz1 - m2.oz0;
739	
740	  const g1 = _buildGableGeometry(m1.ox0, m1.ox1, m1.oz0, m1.oz1, eaveY, slopeRad, ax1);
741	  const g2 = _buildGableGeometry(m2.ox0, m2.ox1, m2.oz0, m2.oz1, eaveY, slopeRad, ax2);
742	
743	  // Valley face — triangular face connecting the inner eave corner to the two ridges.
744	  const rvxM = rv.xMm / 1000,
745	    rvzM = rv.yMm / 1000;
746	  const halfSpan1 = ax1 ? (m1.oz1 - m1.oz0) / 2 : (m1.ox1 - m1.ox0) / 2;
747	  const ridgeY1 = eaveY + halfSpan1 * Math.tan(slopeRad);
748	  const ridgeMid1x = ax1 ? rvxM : (m1.ox0 + m1.ox1) / 2;
749	  const ridgeMid1z = ax1 ? (m1.oz0 + m1.oz1) / 2 : rvzM;
750	  const halfSpan2 = ax2 ? (m2.oz1 - m2.oz0) / 2 : (m2.ox1 - m2.ox0) / 2;
751	  const ridgeY2 = eaveY + halfSpan2 * Math.tan(slopeRad);
752	  const ridgeMid2x = ax2 ? rvxM : (m2.ox0 + m2.ox1) / 2;
753	  const ridgeMid2z = ax2 ? (m2.oz0 + m2.oz1) / 2 : rvzM;
754	
755	  const valleyPositions = [
756	    rvxM,
757	    eaveY,
758	    rvzM,
759	    ridgeMid1x,
760	    ridgeY1,
761	    ridgeMid1z,
762	    ridgeMid2x,
763	    ridgeY2,
764	    ridgeMid2z,
765	  ];
766	  const gv = new THREE.BufferGeometry();
767	  gv.setAttribute('position', new THREE.Float32BufferAttribute(valleyPositions, 3));
768	  gv.computeVertexNormals();
769	
770	  const merged = mergeGeometries([g1, g2, gv]);
771	  if (!merged) {
772	    // mergeGeometries can return null if all inputs are empty.
773	    return g1;
774	  }
775	  return merged;
776	}
