780	export function makeRoofMassMesh(
781	  roof: Extract<Element, { kind: 'roof' }>,
782	  elementsById: Record<string, Element>,
783	  paint: ViewportPaintBundle | null,
784	): THREE.Mesh {
785	  const rawPts = roof.footprintMm ?? [];
786	
787	  const ovMm = THREE.MathUtils.clamp(roof.overhangMm ?? 0, 0, 5000);
788	
789	  // Offset footprint outward in plan space, then derive AABB for simple cases.
790	  const offsetPts = ovMm > 0 && rawPts.length >= 3 ? offsetPolygonMm(rawPts, ovMm) : rawPts;
791	  const b = xzBoundsMm(offsetPts.length >= 3 ? offsetPts : rawPts);
792	
793	  const refElev = elevationMForLevel(roof.referenceLevelId, elementsById);
794	  // Eave plate = top of the tallest wall at the reference level.
795	  const wallsAtRefLevel = Object.values(elementsById).filter(
796	    (e): e is WallElem => e.kind === 'wall' && (e as WallElem).levelId === roof.referenceLevelId,
797	  );
798	  const wallTopM =
799	    wallsAtRefLevel.length > 0
800	      ? Math.max(...wallsAtRefLevel.map((w) => (w.heightMm ?? 0) / 1000))
801	      : 0;
802	  const eaveY = refElev + wallTopM;
803	
804	  const ox0 = b.minX / 1000;
805	  const ox1 = b.maxX / 1000;
806	  const oz0 = b.minZ / 1000;
807	  const oz1 = b.maxZ / 1000;
808	
809	  let geom: THREE.BufferGeometry;
810	  if (roof.roofGeometryMode === 'flat') {
811	    const slabThick = 0.15;
812	    geom = new THREE.BoxGeometry(ox1 - ox0, slabThick, oz1 - oz0);
813	    geom.translate((ox0 + ox1) / 2, eaveY + slabThick / 2, (oz0 + oz1) / 2);
814	  } else {
815	    const slopeRad = (THREE.MathUtils.clamp(Number(roof.slopeDeg ?? 25), 5, 70) * Math.PI) / 180;
816	    const spanXm = b.spanX / 1000;
817	    const spanZm = b.spanZ / 1000;
818	
819	    // Ridge axis: explicit field takes priority; else use longer plan axis.
820	    let ridgeAlongX: boolean;
821	    if (roof.ridgeAxis === 'x') ridgeAlongX = true;
822	    else if (roof.ridgeAxis === 'z') ridgeAlongX = false;
823	    else ridgeAlongX = spanXm >= spanZm;
824	
825	    // L-shape detection: polygon area / convex hull area < 0.85
826	    const isLShape = rawPts.length >= 6 && _compactnessRatio(rawPts) < 0.85;
827	
828	    if (isLShape) {
829	      geom = _buildLShapeGeometry(rawPts, ovMm, eaveY, slopeRad);
830	    } else if (roof.roofGeometryMode === 'hip') {
831	      geom = _buildHipGeometry(ox0, ox1, oz0, oz1, eaveY, slopeRad, ridgeAlongX);
832	    } else {
833	      geom = _buildGableGeometry(ox0, ox1, oz0, oz1, eaveY, slopeRad, ridgeAlongX);
834	    }
835	  }
836	
837	  const roofColor =
838	    roof.materialKey ??
839	    (roof.roofGeometryMode === 'flat' ? '#d8d8d4' : categoryColorOr(paint, 'roof'));
840	  const roofIsLight = !!roof.materialKey;
841	
842	  const mesh = new THREE.Mesh(
843	    geom,
844	    new THREE.MeshStandardMaterial({
845	      color: roofColor,
846	      transparent: true,
847	      opacity: 0.94,
848	      roughness: roofIsLight ? 0.9 : (paint?.categories.roof.roughness ?? 0.74),
849	      metalness: paint?.categories.roof.metalness ?? 0.0,
850	      envMapIntensity: roofIsLight ? 0.1 : 1.0,
851	      side: THREE.DoubleSide,
852	    }),
853	  );
854	  mesh.userData.bimPickId = roof.id;
855	  addEdges(mesh);
856	  return mesh;
857	}
