859	export function makeStairVolumeMesh(
860	  stair: Extract<Element, { kind: 'stair' }>,
861	  elementsById: Record<string, Element>,
862	  paint: ViewportPaintBundle | null,
863	): THREE.Group {
864	  const group = new THREE.Group();
865	
866	  const sx = stair.runStartMm.xMm / 1000;
867	  const sz = stair.runStartMm.yMm / 1000;
868	  const ex = stair.runEndMm.xMm / 1000;
869	  const ez = stair.runEndMm.yMm / 1000;
870	  const dx = ex - sx;
871	  const dz = ez - sz;
872	  const runLen = Math.max(1e-3, Math.hypot(dx, dz));
873	  const stairWidth = THREE.MathUtils.clamp(stair.widthMm / 1000, 0.3, 4);
874	
875	  const baseLevelElev = elevationMForLevel(stair.baseLevelId, elementsById);
876	  const topLevelElev = elevationMForLevel(stair.topLevelId, elementsById);
877	  const totalRise = Math.max(Math.abs(topLevelElev - baseLevelElev), 0.1);
878	
879	  const riserCount = Math.max(
880	    Math.round((totalRise * 1000) / (stair.riserMm > 0 ? stair.riserMm : 175)),
881	    2,
882	  );
883	  const riserH = totalRise / riserCount;
884	  const treadDepth = runLen / riserCount;
885	  const treadThick = 0.04;
886	  const angle = Math.atan2(dz, dx);
887	
888	  const mat = new THREE.MeshStandardMaterial({
889	    color: categoryColorOr(paint, 'stair'),
890	    roughness: paint?.categories.stair.roughness ?? 0.85,
891	  });
892	
893	  const treadGeom = new THREE.BoxGeometry(treadDepth, treadThick, stairWidth);
894	  for (let i = 0; i < riserCount; i++) {
895	    const treadMesh = new THREE.Mesh(treadGeom, mat);
896	    const cx = sx + ((i + 0.5) / riserCount) * dx;
897	    const cz = sz + ((i + 0.5) / riserCount) * dz;
898	    // top surface of tread i sits at baseLevelElev + (i+1)*riserH
899	    const cy = baseLevelElev + (i + 1) * riserH - treadThick / 2;
900	    treadMesh.position.set(cx, cy, cz);
901	    treadMesh.rotation.y = angle;
902	    treadMesh.castShadow = true;
903	    treadMesh.receiveShadow = true;
904	    treadMesh.userData.bimPickId = stair.id;
905	    addEdges(treadMesh);
906	    group.add(treadMesh);
907	  }
908	
909	  // Side stringer plates offset laterally by ±stairWidth/2 along local Z
910	  // Local Z world direction for rotation.y = angle: (sin angle, 0, cos angle) = (dz/runLen, 0, dx/runLen)
911	  const stringerGeom = new THREE.BoxGeometry(runLen, totalRise, 0.025);
912	  const midCx = (sx + ex) / 2;
913	  const midCz = (sz + ez) / 2;
914	  const midCy = baseLevelElev + totalRise / 2;
915	  const perpX = dz / runLen;
916	  const perpZ = dx / runLen;
917	
918	  for (const side of [-1, 1] as const) {
919	    const stringer = new THREE.Mesh(stringerGeom, mat);
920	    stringer.position.set(
921	      midCx + perpX * side * (stairWidth / 2),
922	      midCy,
923	      midCz + perpZ * side * (stairWidth / 2),
924	    );
925	    stringer.rotation.y = angle;
926	    stringer.castShadow = true;
927	    stringer.receiveShadow = true;
928	    stringer.userData.bimPickId = stair.id;
929	    addEdges(stringer);
930	    group.add(stringer);
931	  }
932	
933	  group.userData.bimPickId = stair.id;
934	  return group;
935	}
