937	export function addCladdingBoards(
938	  mesh: THREE.Mesh,
939	  wallLenM: number,
940	  wallHeightM: number,
941	  wallThickM: number,
942	  boardWidthMm = 120,
943	  gapMm = 10,
944	  colorOverride?: string,
945	): void {
946	  const pitchM = (boardWidthMm + gapMm) / 1000;
947	  const count = Math.max(1, Math.floor(wallLenM / pitchM));
948	  const boardProtrude = 0.012; // 12 mm proud of wall face
949	  const boardH = wallHeightM - 0.05;
950	  const boardD = pitchM - 0.002; // slight gap between boards
951	  const color = colorOverride ?? readToken('--cat-timber-cladding', '#8B6340');
952	  const isOverride = colorOverride !== undefined;
953	  const mat = new THREE.MeshStandardMaterial({
954	    color,
955	    roughness: isOverride ? 0.92 : 0.85,
956	    metalness: 0.0,
957	    envMapIntensity: isOverride ? 0.08 : 1.0,
958	  });
959	
960	  for (let i = 0; i < count; i++) {
961	    const board = new THREE.Mesh(new THREE.BoxGeometry(boardD, boardH, boardProtrude), mat);
962	    board.position.set((i + 0.5) * pitchM - wallLenM / 2, 0, wallThickM / 2 + boardProtrude / 2);
963	    addEdges(board);
964	    mesh.add(board);
965	  }
966	}
