968	export function makeSlopedWallMesh(
969	  wall: WallElem,
970	  roof: Extract<Element, { kind: 'roof' }>,
971	  elevM: number,
972	  paint: ViewportPaintBundle | null,
973	  elementsById: Record<string, Element>,
974	): THREE.Mesh {
975	  const sx = wall.start.xMm;
976	  const sz = wall.start.yMm;
977	  const ex = wall.end.xMm;
978	  const ez = wall.end.yMm;
979	
980	  const dx = ex - sx;
981	  const dz = ez - sz;
982	  const len = Math.max(1, Math.hypot(dx, dz));
983	  const ux = dx / len;
984	  const uz = dz / len;
985	  const nx = -uz;
986	  const nz = ux;
987	
988	  const thick = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.05, 2);
989	  const halfT = thick / 2;
990	
991	  const hStart = roofHeightAtPoint(roof, elementsById, sx, sz);
992	  const hEnd = roofHeightAtPoint(roof, elementsById, ex, ez);
993	
994	  const yBase = elevM;
995	
996	  const sxF = sx / 1000 + nx * halfT;
997	  const szF = sz / 1000 + nz * halfT;
998	  const exF = ex / 1000 + nx * halfT;
999	  const ezF = ez / 1000 + nz * halfT;
1000	  const sxB = sx / 1000 - nx * halfT;
1001	  const szB = sz / 1000 - nz * halfT;
1002	  const exB = ex / 1000 - nx * halfT;
1003	  const ezB = ez / 1000 - nz * halfT;
1004	
1005	  const positions = new Float32Array([
1006	    sxF,
1007	    yBase,
1008	    szF, // 0 start-front-base
1009	    exF,
1010	    yBase,
1011	    ezF, // 1 end-front-base
1012	    exF,
1013	    hEnd,
1014	    ezF, // 2 end-front-top
1015	    sxF,
1016	    hStart,
1017	    szF, // 3 start-front-top
1018	    sxB,
1019	    yBase,
1020	    szB, // 4 start-back-base
1021	    exB,
1022	    yBase,
1023	    ezB, // 5 end-back-base
1024	    exB,
1025	    hEnd,
1026	    ezB, // 6 end-back-top
1027	    sxB,
1028	    hStart,
1029	    szB, // 7 start-back-top
1030	  ]);
1031	
1032	  const indices = new Uint16Array([
1033	    0,
1034	    1,
1035	    2,
1036	    0,
1037	    2,
1038	    3, // front face
1039	    5,
1040	    4,
1041	    7,
1042	    5,
1043	    7,
1044	    6, // back face
1045	    4,
1046	    0,
1047	    3,
1048	    4,
1049	    3,
1050	    7, // left cap (start)
1051	    1,
1052	    5,
1053	    6,
1054	    1,
1055	    6,
1056	    2, // right cap (end)
1057	    4,
1058	    5,
1059	    1,
1060	    4,
1061	    1,
1062	    0, // bottom
1063	    3,
1064	    2,
1065	    6,
1066	    3,
1067	    6,
1068	    7, // top (sloped)
1069	  ]);
1070	
1071	  const geom = new THREE.BufferGeometry();
1072	  geom.setAttribute('position', new THREE.BufferAttribute(positions, 3));
1073	  geom.setIndex(new THREE.BufferAttribute(indices, 1));
1074	  geom.computeVertexNormals();
1075	
1076	  const mat = new THREE.MeshStandardMaterial({
1077	    color: categoryColorOr(paint, 'wall'),
1078	    roughness: paint?.categories.wall.roughness ?? 0.85,
1079	    metalness: paint?.categories.wall.metalness ?? 0.0,
1080	  });
1081	  const mesh = new THREE.Mesh(geom, mat);
1082	  mesh.userData.bimPickId = wall.id;
1083	  addEdges(mesh);
1084	  return mesh;
1085	}
1086	
1087	export function makeWallMesh(
1088	  wall: WallElem,
1089	  elevM: number,
1090	  paint: ViewportPaintBundle | null,
1091	  elementsById?: Record<string, Element>,
1092	): THREE.Mesh {
1093	  if (wall.roofAttachmentId && elementsById) {
1094	    const roof = elementsById[wall.roofAttachmentId];
1095	    if (roof?.kind === 'roof') {
1096	      return makeSlopedWallMesh(
1097	        wall,
1098	        roof as Extract<Element, { kind: 'roof' }>,
1099	        elevM,
1100	        paint,
1101	        elementsById,
1102	      );
1103	    }
1104	  }
1105	  const sx = wall.start.xMm / 1000;
1106	  const sz = wall.start.yMm / 1000;
1107	  const ex = wall.end.xMm / 1000;
1108	  const ez = wall.end.yMm / 1000;
1109	  const dx = ex - sx;
1110	  const dz = ez - sz;
1111	  const len = Math.max(0.001, Math.hypot(dx, dz));
1112	  const thick = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.05, 2);
1113	
1114	  const baseOff = (wall.baseConstraintOffsetMm ?? 0) / 1000;
1115	  const yBase = elevM + baseOff;
1116	  let height: number;
1117	  if (wall.topConstraintLevelId && elementsById) {
1118	    const topLvl = elementsById[wall.topConstraintLevelId];
1119	    const topElevM = topLvl?.kind === 'level' ? topLvl.elevationMm / 1000 : elevM;
1120	    const topOff = (wall.topConstraintOffsetMm ?? 0) / 1000;
1121	    height = THREE.MathUtils.clamp(topElevM + topOff - yBase, 0.25, 40);
1122	  } else {
1123	    height = THREE.MathUtils.clamp(wall.heightMm / 1000, 0.25, 40);
1124	  }
1125	
1126	  const locFrac = locationLineOffsetFrac(wall.locationLine ?? 'wall-centerline');
1127	  const perpX = (-dz / len) * locFrac * thick;
1128	  const perpZ = (dx / len) * locFrac * thick;
1129	
1130	  const isWhite = wall.materialKey === 'white_cladding' || wall.materialKey === 'white_render';
1131	  const wallBaseColor = isWhite ? '#f4f4f0' : categoryColorOr(paint, 'wall');
1132	  const mesh = new THREE.Mesh(
1133	    new THREE.BoxGeometry(len, height, thick),
1134	    new THREE.MeshStandardMaterial({
1135	      color: wallBaseColor,
1136	      roughness: isWhite ? 0.92 : (paint?.categories.wall.roughness ?? 0.85),
1137	      metalness: paint?.categories.wall.metalness ?? 0.0,
1138	      envMapIntensity: isWhite ? 0.08 : 1.0,
1139	    }),
1140	  );
1141	  mesh.position.set(sx + dx / 2 + perpX, yBase + height / 2, sz + dz / 2 + perpZ);
1142	  mesh.rotation.y = Math.atan2(dz, dx);
1143	  mesh.userData.bimPickId = wall.id;
1144	  addEdges(mesh);
1145	  if (wall.materialKey === 'timber_cladding') addCladdingBoards(mesh, len, height, thick);
1146	  else if (wall.materialKey === 'white_cladding')
1147	    addCladdingBoards(mesh, len, height, thick, 120, 10, '#f4f4f0');
1148	
1149	  // Slab edge strip: thin horizontal band at the base of every elevated wall,
1150	  // expressing the floor plate at the level transition (e.g. 1st→2nd floor).
1151	  if (yBase > 0.01) {
1152	    const edgeH = 0.12; // 120 mm deep band
1153	    const edgeP = 0.03; // 30 mm projection proud of wall face
1154	    const edgeMat = new THREE.MeshStandardMaterial({ color: '#c8c8c4', roughness: 0.6 });
1155	    const edgeMesh = new THREE.Mesh(new THREE.BoxGeometry(len, edgeH, thick + edgeP * 2), edgeMat);
1156	    edgeMesh.position.set(0, -height / 2 + edgeH / 2, 0);
1157	    addEdges(edgeMesh);
1158	    mesh.add(edgeMesh);
1159	  }
1160	
1161	  return mesh;
1162	}
1163	
1164	export function makeCurtainWallMesh(
1165	  wall: WallElem,
1166	  elevM: number,
1167	  paint: ViewportPaintBundle | null,
1168	  elementsById?: Record<string, Element>,
1169	): THREE.Group {
1170	  const sx = wall.start.xMm / 1000;
1171	  const sz = wall.start.yMm / 1000;
1172	  const ex = wall.end.xMm / 1000;
1173	  const ez = wall.end.yMm / 1000;
1174	  const dx = ex - sx;
1175	  const dz = ez - sz;
1176	  const len = Math.max(0.001, Math.hypot(dx, dz));
1177	  const height = THREE.MathUtils.clamp(wall.heightMm / 1000, 0.25, 40);
1178	  const thick = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.05, 2);
1179	  const yaw = Math.atan2(dz, dx);
1180	
1181	  const group = new THREE.Group();
1182	  group.userData.bimPickId = wall.id;
1183	
1184	  const glassMat = new THREE.MeshStandardMaterial({
1185	    color: 0x88ccee,
1186	    transparent: true,
1187	    opacity: 0.32,
1188	    roughness: 0.05,
1189	    metalness: 0.1,
1190	    side: THREE.DoubleSide,
1191	  });
1192	  const glassMesh = new THREE.Mesh(new THREE.PlaneGeometry(len, height), glassMat);
1193	  glassMesh.position.set(sx + dx / 2, elevM + height / 2, sz + dz / 2);
1194	  glassMesh.rotation.y = yaw;
1195	  group.add(glassMesh);
1196	
1197	  const mullionMat = new THREE.MeshStandardMaterial({
1198	    color: categoryColorOr(paint, 'wall'),
1199	    roughness: paint?.categories.wall.roughness ?? 0.8,
1200	    metalness: paint?.categories.wall.metalness ?? 0.0,
1201	  });
1202	
1203	  const PANEL_W = 1.5;
1204	  const PANEL_H = 1.2;
1205	  const MW = 0.06;
1206	
1207	  // Vertical mullions at bay divisions
1208	  const vCount =
1209	    wall.curtainWallVCount != null
1210	      ? Math.max(1, wall.curtainWallVCount)
1211	      : Math.max(1, Math.round(len / PANEL_W));
1212	  for (let i = 0; i <= vCount; i++) {
1213	    const t = i / vCount;
1214	    const vm = new THREE.Mesh(new THREE.BoxGeometry(MW, height, thick), mullionMat);
1215	    vm.position.set(sx + t * dx, elevM + height / 2, sz + t * dz);
1216	    vm.rotation.y = yaw;
1217	    addEdges(vm);
1218	    group.add(vm);
1219	  }
1220	
1221	  // Horizontal mullions at floor divisions
1222	  const hCount =
1223	    wall.curtainWallHCount != null
1224	      ? Math.max(1, wall.curtainWallHCount)
1225	      : Math.max(1, Math.round(height / PANEL_H));
1226	  for (let i = 0; i <= hCount; i++) {
1227	    const y = elevM + i * (height / hCount);
1228	    const hm = new THREE.Mesh(new THREE.BoxGeometry(len, MW, thick), mullionMat);
1229	    hm.position.set(sx + dx / 2, y, sz + dz / 2);
1230	    hm.rotation.y = yaw;
1231	    addEdges(hm);
1232	    group.add(hm);
1233	  }
1234	
1235	  // Gable triangle glazing: when the wall has a roofAttachmentId pointing at a
1236	  // gable/hip roof, extend the glass + mullions up into the triangular zone above
1237	  // the rectangular wall top (eave to ridge).
1238	  if (wall.roofAttachmentId && elementsById) {
1239	    const roofEl = elementsById[wall.roofAttachmentId];
1240	    if (roofEl?.kind === 'roof' && roofEl.roofGeometryMode !== 'flat') {
1241	      const roof = roofEl as Extract<Element, { kind: 'roof' }>;
1242	      const eaveYw = elevM + height;
1243	
1244	      // Sample N+1 heights along the wall at fine resolution
1245	      const N = Math.max(8, Math.round(len / (PANEL_W / 4)));
1246	      const hSamples: number[] = [];
1247	      for (let i = 0; i <= N; i++) {
1248	        const t = i / N;
1249	        const xMm = wall.start.xMm + t * (wall.end.xMm - wall.start.xMm);
1250	        const zMm = wall.start.yMm + t * (wall.end.yMm - wall.start.yMm);
1251	        hSamples.push(roofHeightAtPoint(roof, elementsById, xMm, zMm));
1252	      }
1253	
1254	      const maxH = Math.max(...hSamples);
1255	      if (maxH > eaveYw + 0.02) {
1256	        // Build glass mesh for the gable triangle zone as quads between sample columns
1257	        const triPositions: number[] = [];
1258	        const triIndices: number[] = [];
1259	        let vIdx = 0;
1260	        for (let i = 0; i < N; i++) {
1261	          const t0 = i / N;
1262	          const t1 = (i + 1) / N;
1263	          const x0w = sx + t0 * dx,
1264	            z0w = sz + t0 * dz;
1265	          const x1w = sx + t1 * dx,
1266	            z1w = sz + t1 * dz;
1267	          const h0 = Math.max(hSamples[i], eaveYw);
1268	          const h1 = Math.max(hSamples[i + 1], eaveYw);
1269	          if (h0 <= eaveYw + 0.001 && h1 <= eaveYw + 0.001) continue;
1270	          // Quad: BL, BR, TR, TL
1271	          triPositions.push(x0w, eaveYw, z0w, x1w, eaveYw, z1w, x1w, h1, z1w, x0w, h0, z0w);
1272	          triIndices.push(vIdx, vIdx + 1, vIdx + 2, vIdx, vIdx + 2, vIdx + 3);
1273	          vIdx += 4;
1274	        }
1275	        if (triPositions.length > 0) {
1276	          const triGeom = new THREE.BufferGeometry();
1277	          triGeom.setAttribute(
1278	            'position',
1279	            new THREE.BufferAttribute(new Float32Array(triPositions), 3),
1280	          );
1281	          triGeom.setIndex(triIndices);
1282	          triGeom.computeVertexNormals();
1283	          group.add(new THREE.Mesh(triGeom, glassMat));
1284	        }
1285	
1286	        // Vertical mullions in the gable triangle zone
1287	        const vCountTri = Math.max(1, Math.round(len / PANEL_W));
1288	        for (let i = 0; i <= vCountTri; i++) {
1289	          const t = i / vCountTri;
1290	          const xMm = wall.start.xMm + t * (wall.end.xMm - wall.start.xMm);
1291	          const zMm = wall.start.yMm + t * (wall.end.yMm - wall.start.yMm);
1292	          const topY = roofHeightAtPoint(roof, elementsById, xMm, zMm);
1293	          if (topY <= eaveYw + 0.02) continue;
1294	          const mullionH = topY - eaveYw;
1295	          const mxw = sx + t * dx;
1296	          const mzw = sz + t * dz;
1297	          const vm = new THREE.Mesh(new THREE.BoxGeometry(MW, mullionH, thick), mullionMat);
1298	          vm.position.set(mxw, eaveYw + mullionH / 2, mzw);
1299	          vm.rotation.y = yaw;
1300	          addEdges(vm);
1301	          group.add(vm);
1302	        }
1303	      }
1304	    }
1305	  }
1306	
1307	  return group;
1308	}
