1361	export function makeRailingMesh(
1362	  railing: Extract<Element, { kind: 'railing' }>,
1363	  elementsById: Record<string, Element>,
1364	  paint: ViewportPaintBundle | null,
1365	): THREE.Group {
1366	  const group = new THREE.Group();
1367	  group.userData.bimPickId = railing.id;
1368	
1369	  const guardH = THREE.MathUtils.clamp((railing.guardHeightMm ?? 1050) / 1000, 0.5, 2.2);
1370	  const pts = railing.pathMm ?? [];
1371	  if (pts.length < 2) return group;
1372	
1373	  const stair = railing.hostedStairId ? elementsById[railing.hostedStairId] : null;
1374	  const baseElev =
1375	    stair?.kind === 'stair' ? elevationMForLevel(stair.baseLevelId, elementsById) : 0;
1376	  const topElev =
1377	    stair?.kind === 'stair' ? elevationMForLevel(stair.topLevelId, elementsById) : baseElev;
1378	
1379	  let totalPlanLen = 0;
1380	  for (let i = 1; i < pts.length; i++) {
1381	    totalPlanLen += Math.hypot(
1382	      (pts[i]!.xMm - pts[i - 1]!.xMm) / 1000,
1383	      (pts[i]!.yMm - pts[i - 1]!.yMm) / 1000,
1384	    );
1385	  }
1386	
1387	  const mat = new THREE.MeshStandardMaterial({
1388	    color: categoryColorOr(paint, 'railing'),
1389	    roughness: 0.35,
1390	    metalness: 0.65,
1391	  });
1392	
1393	  // Pre-compute cumulative parametric t at each vertex for slope interpolation
1394	  const vertexT: number[] = [0];
1395	  let cumForT = 0;
1396	  for (let i = 1; i < pts.length; i++) {
1397	    cumForT += Math.hypot(
1398	      (pts[i]!.xMm - pts[i - 1]!.xMm) / 1000,
1399	      (pts[i]!.yMm - pts[i - 1]!.yMm) / 1000,
1400	    );
1401	    vertexT.push(totalPlanLen > 0 ? cumForT / totalPlanLen : 1);
1402	  }
1403	
1404	  // Square posts at each path vertex
1405	  const postSect = 0.05;
1406	  const postGeom = new THREE.BoxGeometry(postSect, guardH, postSect);
1407	  for (let i = 0; i < pts.length; i++) {
1408	    const t = vertexT[i]!;
1409	    const floorY = baseElev + t * (topElev - baseElev);
1410	    const post = new THREE.Mesh(postGeom, mat);
1411	    post.position.set(pts[i]!.xMm / 1000, floorY + guardH / 2, pts[i]!.yMm / 1000);
1412	    post.castShadow = post.receiveShadow = true;
1413	    post.userData.bimPickId = railing.id;
1414	    addEdges(post);
1415	    group.add(post);
1416	  }
1417	
1418	  // Rail cap segments + balusters between posts
1419	  const capSect = 0.045;
1420	  const balW = 0.012;
1421	  const balSpacing = 0.115;
1422	  const balGeom = new THREE.BoxGeometry(balW, guardH, balW);
1423	
1424	  let cumLen = 0;
1425	  for (let i = 0; i < pts.length - 1; i++) {
1426	    const a = pts[i]!;
1427	    const b = pts[i + 1]!;
1428	    const ax = a.xMm / 1000,
1429	      az = a.yMm / 1000;
1430	    const bx = b.xMm / 1000,
1431	      bz = b.yMm / 1000;
1432	    const planSeg = Math.max(0.001, Math.hypot(bx - ax, bz - az));
1433	    const tA = totalPlanLen > 0 ? cumLen / totalPlanLen : 0;
1434	    cumLen += planSeg;
1435	    const tB = totalPlanLen > 0 ? cumLen / totalPlanLen : 1;
1436	    const floorA = baseElev + tA * (topElev - baseElev);
1437	    const floorB = baseElev + tB * (topElev - baseElev);
1438	    const elevA = floorA + guardH;
1439	    const elevB = floorB + guardH;
1440	    const riseY = elevB - elevA;
1441	
1442	    // Rail cap segment
1443	    const railLen = Math.sqrt(planSeg * planSeg + riseY * riseY);
1444	    const rail = new THREE.Mesh(new THREE.BoxGeometry(railLen, capSect, capSect), mat);
1445	    rail.position.set((ax + bx) / 2, (elevA + elevB) / 2, (az + bz) / 2);
1446	    const dir = new THREE.Vector3(bx - ax, riseY, bz - az).normalize();
1447	    rail.quaternion.setFromUnitVectors(new THREE.Vector3(1, 0, 0), dir);
1448	    rail.castShadow = rail.receiveShadow = true;
1449	    rail.userData.bimPickId = railing.id;
1450	    addEdges(rail);
1451	    group.add(rail);
1452	
1453	    // Evenly spaced balusters between the two posts
1454	    const balCount = Math.max(0, Math.floor(planSeg / balSpacing));
1455	    for (let j = 0; j < balCount; j++) {
1456	      const tLocal = (j + 0.5) / balCount;
1457	      const bxj = ax + tLocal * (bx - ax);
1458	      const bzj = az + tLocal * (bz - az);
1459	      const floorYj = floorA + tLocal * (floorB - floorA);
1460	      const bal = new THREE.Mesh(balGeom, mat);
1461	      bal.position.set(bxj, floorYj + guardH / 2, bzj);
1462	      bal.castShadow = bal.receiveShadow = true;
1463	      bal.userData.bimPickId = railing.id;
1464	      addEdges(bal);
1465	      group.add(bal);
1466	    }
1467	  }
1468	
1469	  return group;
1470	}
