1515	export function makeBalconyMesh(
1516	  balcony: Extract<Element, { kind: 'balcony' }>,
1517	  elementsById: Record<string, Element>,
1518	  paint: ViewportPaintBundle | null,
1519	): THREE.Group {
1520	  const group = new THREE.Group();
1521	  group.userData.bimPickId = balcony.id;
1522	
1523	  const wall = elementsById[balcony.wallId];
1524	  if (wall?.kind !== 'wall') return group;
1525	
1526	  const sx = wall.start.xMm / 1000;
1527	  const sz = wall.start.yMm / 1000;
1528	  const ex = wall.end.xMm / 1000;
1529	  const ez = wall.end.yMm / 1000;
1530	  const dx = ex - sx;
1531	  const dz = ez - sz;
1532	  const len = Math.max(0.001, Math.hypot(dx, dz));
1533	  const ux = dx / len;
1534	  const uz = dz / len;
1535	  // Outward normal: right of walking direction (start→end).
1536	  // For south wall drawn west→east (+X): right = -Z (south). ✓
1537	  const nx = uz;
1538	  const nz = -ux;
1539	  const yaw = Math.atan2(dz, dx);
1540	
1541	  const elevM = balcony.elevationMm / 1000;
1542	  const projM = THREE.MathUtils.clamp((balcony.projectionMm ?? 650) / 1000, 0.1, 3);
1543	  const slabH = THREE.MathUtils.clamp((balcony.slabThicknessMm ?? 150) / 1000, 0.05, 0.5);
1544	  const balH = THREE.MathUtils.clamp((balcony.balustradeHeightMm ?? 1050) / 1000, 0, 2);
1545	
1546	  // Slab: projects outward from wall centerline; top face at elevM.
1547	  const slabCy = elevM - slabH / 2;
1548	  const slabCx = sx + dx / 2 + (nx * projM) / 2;
1549	  const slabCz = sz + dz / 2 + (nz * projM) / 2;
1550	  const slabMat = new THREE.MeshStandardMaterial({ color: '#c8c8c4', roughness: 0.6 });
1551	  const slab = new THREE.Mesh(new THREE.BoxGeometry(len, slabH, projM), slabMat);
1552	  slab.position.set(slabCx, slabCy, slabCz);
1553	  slab.rotation.y = yaw;
1554	  addEdges(slab);
1555	  group.add(slab);
1556	
1557	  // Glass balustrade: frameless glass panel at outer edge, standing on slab top.
1558	  if (balH > 0.01) {
1559	    const glassMat = new THREE.MeshStandardMaterial({
1560	      color: 0x88ccee,
1561	      transparent: true,
1562	      opacity: 0.28,
1563	      roughness: 0.05,
1564	      metalness: 0.1,
1565	      side: THREE.DoubleSide,
1566	    });
1567	    const balThick = 0.018;
1568	    const outerCx = sx + dx / 2 + nx * projM;
1569	    const outerCz = sz + dz / 2 + nz * projM;
1570	    const balGlass = new THREE.Mesh(new THREE.BoxGeometry(len, balH, balThick), glassMat);
1571	    balGlass.position.set(outerCx, elevM + balH / 2, outerCz);
1572	    balGlass.rotation.y = yaw;
1573	    addEdges(balGlass);
1574	    group.add(balGlass);
1575	  }
1576	
1577	  void paint; // unused but kept for API consistency
1578	  return group;
1579	}
