      icon: 'roof',
      hotkey: 'R',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.roof.tooltip'),
    },
    stair: {
      id: 'stair',
      label: t('tools.stair.label'),
      icon: 'stair',
