457	      color: getPlanPalette().dimWitness,
458	      dashSize: dashSpec.dashSize,
459	      gapSize: dashSpec.gapSize,
460	      depthTest: true,
461	    });
462	    const ln = new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts), mat);
463	    ln.computeLineDistances();
464	    grp.add(ln);
465	  }
466	
467	  grp.userData.bimPickId = gl.id;
468	
469	  grp.userData.gridLabel = gl.label;
470	
471	  return grp;
472	}
473	
474	function rebuildPlanMeshesFromWire(
475	  holder: THREE.Object3D,
476	  elementsById: Record<string, Element>,
477	  opts: {
478	    selectedId?: string;
479	    presentation?: PlanPresentationPreset;
480	    wirePrimitives: PlanProjectionPrimitivesV1Wire;
481	    roomFillOpacityScale?: number;
482	    planAnnotationHints?: PlanAnnotationHintsResolved | null;
483	    planTagFontScales?: { opening: number; room: number } | null;
484	  },
485	): void {
486	  while (holder.children.length) holder.remove(holder.children[0]!);
487	
488	  const prim = opts.wirePrimitives;
489	  const presentation = opts.presentation ?? 'default';
490	  const selectedId = opts.selectedId;
491	  const roomFillOpacityScale = opts.roomFillOpacityScale ?? 1;
492	  const ann = opts.planAnnotationHints ?? null;
493	  const tagOpenScale = opts.planTagFontScales?.opening ?? 1;
494	  const tagRoomScale = opts.planTagFontScales?.room ?? 1;
495	
496	  const wallsRaw = Array.isArray(prim.walls) ? (prim.walls as Record<string, unknown>[]) : [];
497	  const wallsByWireId = new Map<string, Extract<Element, { kind: 'wall' }>>();
498	  for (const row of wallsRaw) {
499	    const id = String(row.id ?? '');
500	    if (!id) continue;
501	    wallsByWireId.set(id, wallElemFromWirePrimitive(row));
502	  }
503	
504	  const grids = Array.isArray(prim.gridLines) ? (prim.gridLines as Record<string, unknown>[]) : [];
505	  for (const g of grids) {
506	    const id = String(g.id ?? '');
507	    const gl: Extract<Element, { kind: 'grid_line' }> = {
508	      kind: 'grid_line',
509	      id,
510	      name: 'Grid',
511	      label: typeof g.label === 'string' ? g.label : '',
512	      start: coerceVec2Mm(g.startMm),
513	      end: coerceVec2Mm(g.endMm),
514	      ...(g.levelId !== undefined && g.levelId !== null ? { levelId: String(g.levelId) } : {}),
515	    };
516	    const patRaw = g.linePatternToken ?? g.line_pattern_token;
517	    const linePat = typeof patRaw === 'string' ? patRaw : undefined;
518	    holder.add(gridLineThreeFromPlanWire(gl, linePat));
519	  }
520	
521	  const rooms = Array.isArray(prim.rooms) ? (prim.rooms as Record<string, unknown>[]) : [];
522	  for (const r of rooms) {
523	    const id = String(r.id ?? '');
524	    const outline = outlineMmFromWire(r.outlineMm);
525	    if (outline.length < 2) continue;
526	    const live = elementsById[id];
527	    const roomEl: Extract<Element, { kind: 'room' }> =
528	      live?.kind === 'room'
529	        ? live
530	        : {
531	            kind: 'room',
532	            id,
533	            name: id,
534	            levelId: String(r.levelId ?? ''),
535	            outlineMm: outline,
536	          };
537	    const hexRaw = r.schemeColorHex ?? r.scheme_color_hex;
538	    const schemeHex =
539	      typeof hexRaw === 'string' && /^#[0-9a-fA-F]{6}$/.test(hexRaw.trim())
540	        ? hexRaw.trim()
541	        : undefined;
542	    const mesh = roomMesh(roomEl, presentation, {
543	      schemeColorHex: schemeHex,
544	      roomFillOpacityScale,
545	    });
546	    holder.add(mesh);
547	    if (ann?.roomLabelsVisible === true && typeof mesh.userData.roomLabel === 'object') {
548	      const labelRaw = typeof r.planTagLabel === 'string' ? r.planTagLabel.trim() : '';
549	      if (labelRaw) {
550	        const rl = mesh.userData.roomLabel as { cx?: number; cz?: number };
551	        if (
552	          rl &&
553	          typeof rl.cx === 'number' &&
554	          Number.isFinite(rl.cx) &&
555	          typeof rl.cz === 'number' &&
556	          Number.isFinite(rl.cz)
557	        ) {
558	          holder.add(
559	            planAnnotationLabelSprite(
560	              rl.cx,
561	              rl.cz,
562	              labelRaw,
563	              mesh.userData.bimPickId,
564	              tagRoomScale,
565	            ),
566	          );
567	        }
568	      }
569	    }
570	  }
571	
572	  const floors = Array.isArray(prim.floors) ? (prim.floors as Record<string, unknown>[]) : [];
573	  for (const f of floors) {
574	    const outline = outlineMmFromWire(f.outlineMm);
575	    if (outline.length < 2) continue;
576	    const lwh = Number(f.lineWeightHint ?? f.line_weight_hint ?? 1);
577	    const patRaw = f.linePatternToken ?? f.line_pattern_token;
578	    holder.add(
579	      planFloorRoofOutlineWireGroup(outline, {
580	        kind: 'floor',
581	        pickId: String(f.id ?? ''),
582	        lineWeightHint: lwh,
583	        linePatternToken: typeof patRaw === 'string' ? patRaw : undefined,
584	      }),
585	    );
586	  }
587	
588	  const roofs = Array.isArray(prim.roofs) ? (prim.roofs as Record<string, unknown>[]) : [];
589	  for (const rf of roofs) {
590	    const outline = outlineMmFromWire(rf.footprintMm);
591	    if (outline.length < 2) continue;
592	    const lwh = Number(rf.lineWeightHint ?? rf.line_weight_hint ?? 1);
593	    const patRaw = rf.linePatternToken ?? rf.line_pattern_token;
594	    const supportTokRaw = rf.roofGeometrySupportToken;
595	    const supportTok =
596	      typeof supportTokRaw === 'string' && supportTokRaw.trim() ? supportTokRaw.trim() : null;
597	    const grp = planFloorRoofOutlineWireGroup(outline, {
598	      kind: 'roof',
599	      pickId: String(rf.id ?? ''),
600	      lineWeightHint: lwh,
601	      linePatternToken: typeof patRaw === 'string' ? patRaw : undefined,
602	      roofGeometrySupportToken: supportTok,
603	    });
604	    holder.add(grp);
605	  }
606	
607	  for (const w of wallsByWireId.values()) holder.add(planWallMesh(w, selectedId));
608	
609	  const sepsRaw = Array.isArray(prim.roomSeparations)
610	    ? (prim.roomSeparations as Record<string, unknown>[])
611	    : [];
612	  for (const row of sepsRaw) {
613	    const sid = String(row.id ?? '');
614	    if (!sid) continue;
615	    const sMm = coerceVec2Mm(row.startMm);
616	    const eMm = coerceVec2Mm(row.endMm);
617	    const patRaw = row.linePatternToken ?? row.line_pattern_token;
618	    holder.add(
619	      roomSeparationLineFromMm(sMm, eMm, sid, typeof patRaw === 'string' ? patRaw : undefined),
620	    );
621	  }
622	
623	  const doors = Array.isArray(prim.doors) ? (prim.doors as Record<string, unknown>[]) : [];
624	  for (const d of doors) {
625	    const id = String(d.id ?? '');
626	    const wallId = String(d.wallId ?? '');
627	    const host = resolveWallForWire(wallId, elementsById, wallsByWireId);
628	    const doorEl = elementsById[id];
629	    if (!host || doorEl?.kind !== 'door') continue;
630	    const doorGrp = doorGroupThree(doorEl, host, selectedId, presentation === 'opening_focus');
631	    holder.add(doorGrp);
632	    if (ann?.openingTagsVisible === true) {
633	      const labelRaw = typeof d.planTagLabel === 'string' ? d.planTagLabel.trim() : '';
634	      if (labelRaw) {
635	        doorGrp.updateMatrixWorld(true);
636	        const pos = new THREE.Vector3();
637	        doorGrp.getWorldPosition(pos);
638	        holder.add(planAnnotationLabelSprite(pos.x, pos.z, labelRaw, doorEl.id, tagOpenScale));
639	      }
640	    }
641	  }
642	
643	  const wins = Array.isArray(prim.windows) ? (prim.windows as Record<string, unknown>[]) : [];
644	  for (const w of wins) {
645	    const id = String(w.id ?? '');
646	    const wallId = String(w.wallId ?? '');
647	    const host = resolveWallForWire(wallId, elementsById, wallsByWireId);
648	    const winEl = elementsById[id];
649	    if (!host || winEl?.kind !== 'window') continue;
650	    const winGrp = planWindowMesh(winEl, host, selectedId, presentation === 'opening_focus');
651	    holder.add(winGrp);
652	    if (ann?.openingTagsVisible === true) {
653	      const labelRaw = typeof w.planTagLabel === 'string' ? w.planTagLabel.trim() : '';
654	      if (labelRaw) {
655	        winGrp.updateMatrixWorld(true);
656	        const pos = new THREE.Vector3();
657	        winGrp.getWorldPosition(pos);
658	        holder.add(planAnnotationLabelSprite(pos.x, pos.z, labelRaw, winEl.id, tagOpenScale));
659	      }
660	    }
661	  }
662	
663	  const stairsRaw = Array.isArray(prim.stairs) ? (prim.stairs as Record<string, unknown>[]) : [];
664	  for (const row of stairsRaw) {
665	    const id = String(row.id ?? '');
666	    const live = elementsById[id];
667	    const stairEl: Extract<Element, { kind: 'stair' }> =
668	      live?.kind === 'stair'
669	        ? live
670	        : ({
671	            kind: 'stair',
672	            id,
673	            name: 'Stair',
674	            baseLevelId: String(row.baseLevelId ?? ''),
675	            topLevelId: String(row.topLevelId ?? row.baseLevelId ?? ''),
676	            runStartMm: coerceVec2Mm(row.runStartMm),
