678	            widthMm: Number(row.widthMm ?? 1000),
679	            riserMm: Number(row.riserMm ?? 175),
680	            treadMm: Number(row.treadMm ?? 275),
681	          } as Extract<Element, { kind: 'stair' }>);
682	    const hasDoc =
683	      row.runBearingDegCcFromPlanX !== undefined ||
684	      row.planUpDownLabel !== undefined ||
685	      row.stairPlanBreakVisibilityToken !== undefined ||
686	      row.stairPlanSectionDocumentationLabel !== undefined ||
687	      row.stairDocumentationPlaceholders_v0 !== undefined;
688	    const phRaw = row.stairDocumentationPlaceholders_v0;
689	    const phObj = phRaw && typeof phRaw === 'object' ? (phRaw as Record<string, unknown>) : null;
690	    const wireDoc = hasDoc
691	      ? {
692	          runBearingDegCcFromPlanX:
693	            typeof row.runBearingDegCcFromPlanX === 'number'
694	              ? Number(row.runBearingDegCcFromPlanX)
695	              : undefined,
696	          planUpDownLabel:
697	            typeof row.planUpDownLabel === 'string' ? row.planUpDownLabel : undefined,
698	          stairPlanBreakVisibilityToken:
699	            typeof row.stairPlanBreakVisibilityToken === 'string'
700	              ? row.stairPlanBreakVisibilityToken
701	              : undefined,
702	          stairPlanSectionDocumentationLabel:
703	            typeof row.stairPlanSectionDocumentationLabel === 'string'
704	              ? row.stairPlanSectionDocumentationLabel
705	              : undefined,
706	          stairDocumentationPlaceholders_v0:
707	            phObj &&
