715	                  topLandingFootprintBoundsMm: phObj.topLandingFootprintBoundsMm as BoundsXYmm,
716	                }
717	              : undefined,
718	        }
719	      : undefined;
720	    const g = stairPlanThree(stairEl, elementsById, wireDoc);
721	    if (g) holder.add(g);
