744	function sectionCutPlanThree(sc: Extract<Element, { kind: 'section_cut' }>): THREE.Group {
745	  const group = new THREE.Group();
746	  group.userData.bimPickId = sc.id;
747	
748	  const sx = ux(sc.lineStartMm.xMm);
749	  const sz = uz(sc.lineStartMm.yMm);
750	  const ex = ux(sc.lineEndMm.xMm);
751	  const ez = uz(sc.lineEndMm.yMm);
752	  const Y = PLAN_Y + 0.007;
753	  const color = readToken('--cat-section', '#ef4444');
754	
755	  // Dashed cut body
756	  const linePts = [new THREE.Vector3(sx, Y, sz), new THREE.Vector3(ex, Y, ez)];
757	  const lineGeom = new THREE.BufferGeometry().setFromPoints(linePts);
758	  const lineMat = new THREE.LineDashedMaterial({ color, dashSize: 0.35, gapSize: 0.14 });
759	  const line = new THREE.Line(lineGeom, lineMat);
760	  line.computeLineDistances();
761	  group.add(line);
762	
763	  // Direction along cut and right-hand perpendicular (view direction).
764	  const dx = ex - sx;
765	  const dz = ez - sz;
766	  const len = Math.max(0.001, Math.hypot(dx, dz));
767	  const nx = dx / len;
768	  const nz = dz / len;
769	  const vx = nz;
770	  const vz = -nx;
771	
772	  const STUB = 0.25;
773	  const ARROW = 0.55;
774	  for (const [px, pz] of [
775	    [sx, sz],
776	    [ex, ez],
777	  ] as [number, number][]) {
778	    const stubPts = [
779	      new THREE.Vector3(px - nz * STUB, Y, pz + nx * STUB),
780	      new THREE.Vector3(px + nz * STUB, Y, pz - nx * STUB),
781	    ];
782	    group.add(
783	      new THREE.Line(
784	        new THREE.BufferGeometry().setFromPoints(stubPts),
785	        new THREE.LineBasicMaterial({ color }),
786	      ),
787	    );
788	    const arrPts = [
789	      new THREE.Vector3(px, Y, pz),
790	      new THREE.Vector3(px + vx * ARROW, Y, pz + vz * ARROW),
791	    ];
792	    group.add(
793	      new THREE.Line(
794	        new THREE.BufferGeometry().setFromPoints(arrPts),
795	        new THREE.LineBasicMaterial({ color }),
796	      ),
797	    );
798	  }
799	
800	  return group;
801	}
802	
803	export function rebuildPlanMeshes(
804	  holder: THREE.Object3D,
805	
806	  elementsById: Record<string, Element>,
807	
808	  opts: {
809	    activeLevelId?: string;
810	    selectedId?: string;
811	    presentation?: PlanPresentationPreset;
812	    hiddenSemanticKinds?: ReadonlySet<string>;
813	    wirePrimitives?: PlanProjectionPrimitivesV1Wire | null;
814	    planGraphicHints?: PlanGraphicHintsResolved | null;
815	    planAnnotationHints?: PlanAnnotationHintsResolved | null;
816	    planTagFontScales?: { opening: number; room: number } | null;
817	  },
818	): void {
819	  while (holder.children.length) holder.remove(holder.children[0]!);
820	
821	  const gh = opts.planGraphicHints;
822	  const roomFillOpacityScale = gh?.roomFillOpacityScale ?? 1;
823	  const lineWeightScale = gh?.lineWeightScale ?? 1;
824	
825	  if (opts.wirePrimitives && isPlanProjectionPrimitivesV1(opts.wirePrimitives)) {
826	    rebuildPlanMeshesFromWire(holder, elementsById, {
827	      selectedId: opts.selectedId,
828	      presentation: opts.presentation,
829	      wirePrimitives: opts.wirePrimitives,
830	      roomFillOpacityScale,
831	      planAnnotationHints: opts.planAnnotationHints ?? null,
832	      planTagFontScales: opts.planTagFontScales ?? null,
833	    });
834	    return;
835	  }
836	
837	  const level = opts.activeLevelId;
838	  const presentation = opts.presentation ?? 'default';
839	  const hidden = opts.hiddenSemanticKinds;
840	  const kindHidden = (k: string) => Boolean(hidden?.has(k));
841	
842	  type WallElem = Extract<Element, { kind: 'wall' }>;
843	
844	  const walls = Object.values(elementsById).filter(
845	    (e): e is WallElem =>
846	      e.kind === 'wall' && !kindHidden('wall') && (!level || e.levelId === level),
847	  );
848	
849	  const wallsById: Record<string, WallElem> = Object.fromEntries(walls.map((w) => [w.id, w]));
850	
851	  for (const g of Object.values(elementsById)) {
852	    if (g.kind !== 'grid_line') continue;
853	    if (kindHidden('grid_line')) continue;
854	
855	    if (g.levelId && level && g.levelId !== level) continue;
856	
857	    holder.add(gridLineThree(g));
858	  }
859	
860	  for (const r of Object.values(elementsById)) {
861	    if (r.kind !== 'room') continue;
862	    if (kindHidden('room')) continue;
863	
864	    if (level && r.levelId !== level) continue;
865	
866	    holder.add(roomMesh(r, presentation, { roomFillOpacityScale }));
867	  }
868	
869	  for (const f of Object.values(elementsById)) {
870	    if (f.kind !== 'floor') continue;
871	    if (kindHidden('floor')) continue;
872	
873	    if (level && f.levelId !== level) continue;
874	
875	    holder.add(
876	      horizontalOutlineMesh(
877	        f.boundaryMm,
878	        PLAN_Y + 0.001,
879	        getPlanPalette().floorOutline,
880	        0.16,
881	        f.id,
882	      ),
883	    );
884	  }
885	
886	  for (const rf of Object.values(elementsById)) {
887	    if (rf.kind !== 'roof') continue;
888	    if (kindHidden('roof')) continue;
889	
890	    if (level && rf.referenceLevelId !== level) continue;
891	
892	    holder.add(
893	      horizontalOutlineMesh(
894	        rf.footprintMm,
895	        PLAN_Y + 0.004,
896	        getPlanPalette().roofOutline,
897	        0.2,
898	        rf.id,
899	      ),
900	    );
901	  }
902	
903	  for (const wall of walls) holder.add(planWallMesh(wall, opts.selectedId, lineWeightScale));
904	
905	  for (const rs of Object.values(elementsById)) {
906	    if (rs.kind !== 'room_separation') continue;
907	    if (kindHidden('room_separation')) continue;
908	    if (level && rs.levelId !== level) continue;
909	    holder.add(roomSeparationLineFromMm(rs.start, rs.end, rs.id));
910	  }
911	
912	  for (const d of Object.values(elementsById)) {
913	    if (d.kind !== 'door') continue;
914	    if (kindHidden('door')) continue;
915	
916	    const host = wallsById[d.wallId];
917	
918	    if (!host) continue;
919	
920	    holder.add(doorGroupThree(d, host, opts.selectedId, presentation === 'opening_focus'));
921	  }
922	
923	  for (const win of Object.values(elementsById)) {
924	    if (win.kind !== 'window') continue;
925	    if (kindHidden('window')) continue;
926	
927	    const host = wallsById[win.wallId];
928	
929	    if (!host) continue;
930	
931	    holder.add(planWindowMesh(win, host, opts.selectedId, presentation === 'opening_focus'));
932	  }
933	
934	  for (const st of Object.values(elementsById)) {
935	    if (st.kind !== 'stair') continue;
936	    if (kindHidden('stair')) continue;
937	    if (level && st.baseLevelId !== level) continue;
938	    const g = stairPlanThree(st, elementsById);
939	
940	    if (g) holder.add(g);
941	  }
942	
943	  for (const dm of Object.values(elementsById)) {
944	    if (dm.kind !== 'dimension') continue;
945	    if (kindHidden('dimension')) continue;
946	
947	    if (level && dm.levelId !== level) continue;
948	
949	    holder.add(dimensionsThree(dm));
950	  }
951	
952	  for (const sc of Object.values(elementsById)) {
953	    if (sc.kind !== 'section_cut') continue;
954	    if (kindHidden('section_cut')) continue;
955	    holder.add(sectionCutPlanThree(sc));
956	  }
